/**
 * Workspace Layout Hook
 * Provides workspace-specific layout state with proper store synchronization.
 *
 * Reads directly from the store and provides stable callbacks that update it.
 *
 * Usage:
 * ```typescript
 * const {
 *   contentTab,
 *   selectedFilePath,
 *   setContentTab,
 *   setSelectedFilePath,
 * } = useWorkspaceLayout(workspaceId);
 * ```
 */

import { useCallback } from "react";
import { useShallow } from "zustand/react/shallow";
import {
  useWorkspaceLayoutStore,
  workspaceLayoutActions,
  defaultLayout,
} from "../store/workspaceLayoutStore";
import type { ContentTab } from "../store/workspaceLayoutStore";

interface UseWorkspaceLayoutResult {
  /** Current content panel tab (changes, files, terminal, browser, config, etc.) */
  contentTab: ContentTab;
  /** Currently selected file path (for highlighting in tree) */
  selectedFilePath: string | null;
  /** Whether sidebar is collapsed */
  sidebarCollapsed: boolean;
  /** Whether chat panel is collapsed */
  chatPanelCollapsed: boolean;
  /** Whether content panel is collapsed */
  contentPanelCollapsed: boolean;

  /** Set the active content tab */
  setContentTab: (tab: ContentTab) => void;
  /** Set selected file path */
  setSelectedFilePath: (path: string | null) => void;
  /** Set sidebar collapsed state */
  setSidebarCollapsed: (collapsed: boolean) => void;
  /** Set chat panel collapsed state */
  setChatPanelCollapsed: (collapsed: boolean) => void;
  /** Set content panel collapsed state */
  setContentPanelCollapsed: (collapsed: boolean) => void;
  /** Update multiple layout properties at once */
  updateLayout: (updates: {
    contentTab?: ContentTab;
    selectedFilePath?: string | null;
    sidebarCollapsed?: boolean;
  }) => void;
}

export function useWorkspaceLayout(workspaceId: string | null): UseWorkspaceLayoutResult {
  const layout = useWorkspaceLayoutStore(
    useShallow((state) =>
      workspaceId ? (state.layouts[workspaceId] ?? defaultLayout) : defaultLayout
    )
  );
  const { setLayout } = workspaceLayoutActions;

  const setContentTab = useCallback(
    (tab: ContentTab) => {
      if (workspaceId) {
        setLayout(workspaceId, { activeContentTab: tab });
      }
    },
    [workspaceId, setLayout]
  );

  const setSelectedFilePath = useCallback(
    (path: string | null) => {
      if (workspaceId) {
        setLayout(workspaceId, { selectedFilePath: path });
      }
    },
    [workspaceId, setLayout]
  );

  const setSidebarCollapsed = useCallback(
    (collapsed: boolean) => {
      if (workspaceId) {
        setLayout(workspaceId, { sidebarCollapsed: collapsed });
      }
    },
    [workspaceId, setLayout]
  );

  const setChatPanelCollapsed = useCallback(
    (collapsed: boolean) => {
      if (workspaceId) {
        setLayout(workspaceId, { chatPanelCollapsed: collapsed });
      }
    },
    [workspaceId, setLayout]
  );

  const setContentPanelCollapsed = useCallback(
    (collapsed: boolean) => {
      if (workspaceId) {
        setLayout(workspaceId, { contentPanelCollapsed: collapsed });
      }
    },
    [workspaceId, setLayout]
  );

  const updateLayout = useCallback(
    (updates: {
      contentTab?: ContentTab;
      selectedFilePath?: string | null;
      sidebarCollapsed?: boolean;
    }) => {
      if (!workspaceId) return;

      const layoutUpdates: Parameters<typeof setLayout>[1] = {};

      if (updates.contentTab !== undefined) {
        layoutUpdates.activeContentTab = updates.contentTab;
      }
      if (updates.selectedFilePath !== undefined) {
        layoutUpdates.selectedFilePath = updates.selectedFilePath;
      }
      if (updates.sidebarCollapsed !== undefined) {
        layoutUpdates.sidebarCollapsed = updates.sidebarCollapsed;
      }

      setLayout(workspaceId, layoutUpdates);
    },
    [workspaceId, setLayout]
  );

  return {
    contentTab: layout.activeContentTab ?? defaultLayout.activeContentTab,
    selectedFilePath: layout.selectedFilePath ?? null,
    sidebarCollapsed: layout.sidebarCollapsed,
    chatPanelCollapsed: layout.chatPanelCollapsed ?? false,
    contentPanelCollapsed: layout.contentPanelCollapsed ?? false,

    setContentTab,
    setSelectedFilePath,
    setSidebarCollapsed,
    setChatPanelCollapsed,
    setContentPanelCollapsed,
    updateLayout,
  };
}

import * as React from "react";
import * as ResizablePrimitive from "react-resizable-panels";

import { cn } from "@/shared/lib/utils";

function ResizablePanelGroup({
  className,
  ...props
}: React.ComponentProps<typeof ResizablePrimitive.PanelGroup>) {
  return (
    <ResizablePrimitive.PanelGroup
      data-slot="resizable-panel-group"
      className={cn("flex h-full w-full data-[panel-group-direction=vertical]:flex-col", className)}
      {...props}
    />
  );
}

// forwardRef required in React 18 — ref is a reserved prop stripped from ...props.
// Without this, imperative handles (collapse/expand/resize) silently receive null.
const ResizablePanel = React.forwardRef<
  React.ComponentRef<typeof ResizablePrimitive.Panel>,
  React.ComponentPropsWithoutRef<typeof ResizablePrimitive.Panel>
>(({ ...props }, ref) => (
  <ResizablePrimitive.Panel ref={ref} data-slot="resizable-panel" {...props} />
));
ResizablePanel.displayName = "ResizablePanel";

/**
 * Resize handle — zero-width separator with a gradient line
 * that fades at the top/bottom edges. Appears on hover, brightens on drag.
 * Keyboard accessible (arrow keys) via react-resizable-panels.
 *
 * Uses data-resize-handle-state (inactive | hover | drag) for CSS-only styling.
 */
function ResizableHandle({
  className,
  ...props
}: React.ComponentProps<typeof ResizablePrimitive.PanelResizeHandle>) {
  return (
    <ResizablePrimitive.PanelResizeHandle
      data-slot="resizable-handle"
      className={cn(
        // Zero-width base
        "group relative z-10 flex w-0 flex-shrink-0 items-center justify-center",
        // Vertical mode: zero-height instead
        "data-[panel-group-direction=vertical]:h-0 data-[panel-group-direction=vertical]:w-full",
        // Keyboard focus ring (a11y improvement over the custom hook)
        "focus-visible:ring-ring focus-visible:ring-1 focus-visible:ring-offset-1 focus-visible:outline-hidden",
        className
      )}
      {...props}
    >
      {/* Hit area — wider than the visual line for easier grabbing */}
      <div
        className={cn(
          "absolute inset-y-0 w-3 -translate-x-1/2",
          // Vertical mode: full-width hit area
          "group-data-[panel-group-direction=vertical]:inset-x-0 group-data-[panel-group-direction=vertical]:inset-y-auto group-data-[panel-group-direction=vertical]:h-3 group-data-[panel-group-direction=vertical]:w-full group-data-[panel-group-direction=vertical]:translate-x-0 group-data-[panel-group-direction=vertical]:-translate-y-1/2"
        )}
      />
      {/* Gradient separator: fades at top/bottom for a soft radiance */}
      <div
        className={cn(
          "pointer-events-none absolute inset-y-0 left-1/2 w-px -translate-x-1/2",
          "via-border bg-gradient-to-b from-transparent to-transparent",
          "transition duration-200 ease-out",
          // Drag state: visible with stronger color
          "group-data-[resize-handle-state=drag]:via-foreground/25 group-data-[resize-handle-state=drag]:opacity-100",
          // Hover state: visible with stronger color
          "group-data-[resize-handle-state=hover]:via-foreground/25 group-data-[resize-handle-state=hover]:opacity-100",
          // Inactive: hidden
          "group-data-[resize-handle-state=inactive]:opacity-0",
          // Vertical mode: horizontal gradient line
          "group-data-[panel-group-direction=vertical]:inset-x-0 group-data-[panel-group-direction=vertical]:inset-y-auto group-data-[panel-group-direction=vertical]:left-0 group-data-[panel-group-direction=vertical]:h-px group-data-[panel-group-direction=vertical]:w-full group-data-[panel-group-direction=vertical]:translate-x-0 group-data-[panel-group-direction=vertical]:-translate-y-1/2 group-data-[panel-group-direction=vertical]:bg-gradient-to-r"
        )}
      />
    </ResizablePrimitive.PanelResizeHandle>
  );
}

export { ResizablePanelGroup, ResizablePanel, ResizableHandle };

