 44→  setSidebarCollapsed: (collapsed: boolean) => void;
 45→  /** Set chat panel collapsed state */
 46→  setChatPanelCollapsed: (collapsed: boolean) => void;
 47→  /** Set content panel collapsed state */
 48→  setContentPanelCollapsed: (collapsed: boolean) => void;
 49→  /** Update multiple layout properties at once */
