 57→export function useWorkspaceLayout(workspaceId: string | null): UseWorkspaceLayoutResult {
 58→  const layout = useWorkspaceLayoutStore(
 59→    useShallow((state) =>
 60→      workspaceId ? (state.layouts[workspaceId] ?? defaultLayout) : defaultLayout
 61→    )
 62→  );
 63→  const { setLayout } = workspaceLayoutActions;
 64→
 65→  const setContentTab = useCallback(
 66→    (tab: ContentTab) => {
 67→      if (workspaceId) {
 68→        setLayout(workspaceId, { activeContentTab: tab });
 69→      }
 70→    },
 71→    [workspaceId, setLayout]
 72→  );
 73→
 74→  const setSelectedFilePath = useCallback(
 75→    (path: string | null) => {
 76→      if (workspaceId) {
 77→        setLayout(workspaceId, { selectedFilePath: path });
 78→      }
 79→    },
 80→    [workspaceId, setLayout]
 81→  );
 82→
 83→  const setSidebarCollapsed = useCallback(
 84→    (collapsed: boolean) => {
 85→      if (workspaceId) {
 86→        setLayout(workspaceId, { sidebarCollapsed: collapsed });
 87→      }
 88→    },
 89→    [workspaceId, setLayout]
 90→  );
 91→
 92→  const setChatPanelCollapsed = useCallback(
 93→    (collapsed: boolean) => {
 94→      if (workspaceId) {
 95→        setLayout(workspaceId, { chatPanelCollapsed: collapsed });
 96→      }
 97→    },
 98→    [workspaceId, setLayout]
 99→  );
100→
101→  const setContentPanelCollapsed = useCallback(
102→    (collapsed: boolean) => {
103→      if (workspaceId) {
104→        setLayout(workspaceId, { contentPanelCollapsed: collapsed });
105→      }
106→    },
107→    [workspaceId, setLayout]
108→  );
109→
110→  const updateLayout = useCallback(
111→    (updates: {
112→      contentTab?: ContentTab;
113→      selectedFilePath?: string | null;
114→      sidebarCollapsed?: boolean;
115→    }) => {
116→      if (!workspaceId) return;
117→
118→      const layoutUpdates: Parameters<typeof setLayout>[1] = {};
119→
120→      if (updates.contentTab !== undefined) {
121→        layoutUpdates.activeContentTab = updates.contentTab;
122→      }
123→      if (updates.selectedFilePath !== undefined) {
124→        layoutUpdates.selectedFilePath = updates.selectedFilePath;
125→      }
126→      if (updates.sidebarCollapsed !== undefined) {
127→        layoutUpdates.sidebarCollapsed = updates.sidebarCollapsed;
128→      }
129→
130→      setLayout(workspaceId, layoutUpdates);
131→    },
132→    [workspaceId, setLayout]
133→  );
134→
135→  return {
136→    contentTab: layout.activeContentTab ?? defaultLayout.activeContentTab,
137→    selectedFilePath: layout.selectedFilePath ?? null,
138→    sidebarCollapsed: layout.sidebarCollapsed,
139→    chatPanelCollapsed: layout.chatPanelCollapsed ?? false,
140→    contentPanelCollapsed: layout.contentPanelCollapsed ?? false,
141→
142→    setContentTab,
143→    setSelectedFilePath,
144→    setSidebarCollapsed,
145→    setChatPanelCollapsed,
146→    setContentPanelCollapsed,
147→    updateLayout,
148→  };
149→}
