 19→
 20→interface FileEntry {
 21→  path: string;
 22→  name: string;
 23→  status: "added" | "modified" | "deleted";
 24→  additions: number;
 25→  deletions: number;
 26→}
 27→
 28→interface FolderGroup {
 29→  folder: string;
 30→  files: FileEntry[];
 31→}
 32→
 33→/** Determine change status from additions/deletions */
 34→function getChangeStatus(change: FileChange): "added" | "modified" | "deleted" {
 35→  if (change.additions > 0 && change.deletions === 0) return "added";
 36→  if (change.deletions > 0 && change.additions === 0) return "deleted";
 37→  return "modified";
 38→}
 39→
 40→/** Color for status dot — uses semantic tokens for light/dark compatibility */
 41→const STATUS_COLORS: Record<string, string> = {
 42→  added: "bg-success",
 43→  modified: "bg-warning",
 44→  deleted: "bg-destructive",
 45→};
 46→
 47→/** Group flat file changes into folder groups */
 48→function groupByFolder(fileChanges: FileChange[]): FolderGroup[] {
 49→  const folderMap = new Map<string, FileEntry[]>();
 50→
 51→  for (const change of fileChanges) {
 52→    const path = change.file || change.file_path || "";
 53→    if (!path) continue;
 54→
 55→    const lastSlash = path.lastIndexOf("/");
 56→    const folder = lastSlash > 0 ? path.substring(0, lastSlash) : "";
 57→    const name = lastSlash > 0 ? path.substring(lastSlash + 1) : path;
 58→
 59→    const files = folderMap.get(folder) ?? [];
 60→    files.push({
 61→      path,
 62→      name,
 63→      status: getChangeStatus(change),
 64→      additions: change.additions,
 65→      deletions: change.deletions,
 66→    });
 67→    folderMap.set(folder, files);
 68→  }
 69→
 70→  // Sort folders alphabetically, root files ("") last
 71→  const groups: FolderGroup[] = [];
 72→  const sortedFolders = [...folderMap.keys()].sort((a, b) => {
 73→    if (a === "") return 1;
 74→    if (b === "") return -1;
 75→    return a.localeCompare(b);
 76→  });
 77→
 78→  for (const folder of sortedFolders) {
 79→    const files = folderMap.get(folder)!;
 80→    files.sort((a, b) => a.name.localeCompare(b.name));
 81→    groups.push({ folder, files });
 82→  }
 83→
 84→  return groups;
 85→}
 86→
 87→export function DiffFilesTree({ fileChanges, selectedFile, onFileClick }: DiffFilesTreeProps) {
 88→  const [collapsedFolders, setCollapsedFolders] = useState<Set<string>>(new Set());
 89→
 90→  const groups = useMemo(() => groupByFolder(fileChanges), [fileChanges]);
 91→
 92→  const toggleFolder = useCallback((folder: string) => {
 93→    setCollapsedFolders((prev) => {
 94→      const next = new Set(prev);
 95→      if (next.has(folder)) {
 96→        next.delete(folder);
 97→      } else {
 98→        next.add(folder);
 99→      }
100→      return next;
101→    });
102→  }, []);
103→
104→  return (
105→    <div className="flex h-full flex-col overflow-hidden">
106→      {/* File list — no header, keeps it clean */}
107→      <div className="flex-1 overflow-y-auto py-1">
108→        {groups.map((group) => (
109→          <FolderGroupView
110→            key={group.folder || "__root__"}
111→            group={group}
112→            collapsed={collapsedFolders.has(group.folder)}
113→            onToggle={toggleFolder}
114→            selectedFile={selectedFile}
115→            onFileClick={onFileClick}
116→          />
117→        ))}
118→      </div>
119→    </div>
120→  );
121→}
122→
123→function FolderGroupView({
124→  group,
