132→  onToggle: (folder: string) => void;
133→  selectedFile: string | null;
134→  onFileClick: (path: string) => void;
135→}) {
136→  const isRoot = group.folder === "";
137→
138→  return (
139→    <div>
140→      {/* Folder header — skip for root-level files */}
141→      {!isRoot && (
142→        <button
143→          type="button"
144→          onClick={() => onToggle(group.folder)}
145→          className="text-text-muted hover:text-text-secondary ease flex h-6 w-full items-center gap-1.5 px-3 text-left transition-colors duration-150"
146→        >
147→          {collapsed ? (
148→            <ChevronRight className="text-text-muted/60 h-3 w-3 flex-shrink-0" />
149→          ) : (
150→            <ChevronDown className="text-text-muted/60 h-3 w-3 flex-shrink-0" />
151→          )}
152→          <Folder className="text-text-muted/60 h-3 w-3 flex-shrink-0" />
153→          <span className="min-w-0 truncate text-xs">{group.folder}</span>
154→        </button>
155→      )}
156→
157→      {/* Files — hidden when folder is collapsed */}
158→      {!collapsed &&
159→        group.files.map((file) => (
160→          <button
161→            key={file.path}
162→            type="button"
163→            onClick={() => onFileClick(file.path)}
164→            className={cn(
165→              "ease flex h-6 w-full items-center gap-1.5 text-left transition-colors duration-150",
166→              isRoot ? "px-3" : "pr-3 pl-8",
167→              selectedFile === file.path
168→                ? "bg-bg-elevated text-text-secondary"
169→                : "text-text-muted hover:text-text-secondary"
170→            )}
171→          >
172→            <span
173→              className={cn("h-1.5 w-1.5 flex-shrink-0 rounded-full", STATUS_COLORS[file.status])}
174→            />
175→            <span
176→              className={cn(
177→                "min-w-0 flex-1 truncate text-xs",
178→                file.status === "deleted" && "line-through opacity-50"
179→              )}
180→            >
181→              {file.name}
182→            </span>
183→            {(file.additions > 0 || file.deletions > 0) && (
184→              <span className="flex flex-shrink-0 items-center gap-1 font-mono text-[10px] tabular-nums opacity-50">
185→                {file.additions > 0 && <span className="text-success">+{file.additions}</span>}
