  1→/**
  2→ * AllFilesDiffViewer — Scrollable container for all changed files' diffs.
  3→ *
  4→ * Renders each changed file as an AllDiffFileSection with lazy loading.
  5→ * Exposes `scrollToFile(path)` via ref for bidirectional sync with the file tree.
  6→ * Tracks which file is currently visible and reports it via `onActiveFileChange`.
  7→ *
  8→ * Scroll-spy: centralized scroll listener finds the topmost visible section
  9→ * and syncs active file state to the sidebar tree.
 10→ *
 11→ * Performance: IntersectionObserver lazy loading per section, React.memo,
 12→ * rAF-throttled scroll spy.
 13→ */
 14→
 15→import { forwardRef, useImperativeHandle, useRef, useCallback, useState, useEffect } from "react";
 16→import { ChevronsUpDown } from "lucide-react";
 17→import { AllDiffFileSection } from "./AllDiffFileSection";
 18→import { workspaceLayoutActions } from "../store";
 19→import type { FileChange } from "@/shared/types";
 20→
 21→export interface AllFilesDiffViewerRef {
 22→  scrollToFile: (path: string) => void;
 23→}
 24→
 25→interface AllFilesDiffViewerProps {
 26→  workspaceId: string;
 27→  fileChanges: FileChange[];
 28→  /** Hide the header bar (file count, collapse/expand). Used when
 29→   *  the viewer is embedded inside ChangesView which has its own chrome. */
 30→  hideHeader?: boolean;
 31→  onActiveFileChange?: (filePath: string | null) => void;
 32→  /** File to scroll to on mount (one-shot) */
 33→  initialScrollTarget?: string;
 34→}
 35→
 36→export const AllFilesDiffViewer = forwardRef<AllFilesDiffViewerRef, AllFilesDiffViewerProps>(
 37→  function AllFilesDiffViewer(
 38→    { workspaceId, fileChanges, hideHeader, onActiveFileChange, initialScrollTarget },
 39→    ref
 40→  ) {
 41→    const sectionRefsMap = useRef(new Map<string, HTMLDivElement>());
 42→    const scrollContainerRef = useRef<HTMLDivElement>(null);
 43→    const [activeFile, setActiveFile] = useState<string | null>(null);
 44→    // Key counter for collapse-all/expand-all — incrementing remounts all sections expanded
 45→    const [expandStateKey, setExpandStateKey] = useState(0);
 46→
 47→    // Ref-based stable wrappers for props that change identity on refetch.
 48→    const workspaceIdRef = useRef(workspaceId);
 49→    const fileChangesRef = useRef(fileChanges);
 50→    const onActiveFileChangeRef = useRef(onActiveFileChange);
 51→
 52→    useEffect(() => {
 53→      workspaceIdRef.current = workspaceId;
 54→      fileChangesRef.current = fileChanges;
 55→      onActiveFileChangeRef.current = onActiveFileChange;
 56→    });
 57→
 58→    // Clear ref maps on unmount to prevent stale entries
 59→    useEffect(() => {
 60→      return () => {
 61→        sectionRefsMap.current.clear();
 62→      };
 63→    }, []);
 64→
 65→    // Resolve a file path to its DOM element — ref map first, DOM query fallback.
 66→    const resolveSection = useCallback((path: string): HTMLElement | null => {
 67→      const el = sectionRefsMap.current.get(path);
 68→      if (el) return el;
 69→      return (
 70→        scrollContainerRef.current?.querySelector(`[data-diff-path="${CSS.escape(path)}"]`) ?? null
 71→      );
 72→    }, []);
 73→
 74→    // --- Scroll-spy: centralized scroll event listener ---
 75→    // Finds the topmost section whose top edge is at or above the container's
 76→    // vertical midpoint. More reliable than distributed IntersectionObservers
 77→    // in memoized children with content-visibility: auto.
 78→    const activeFileRef = useRef<{ workspaceId: string; path: string | null }>({
 79→      workspaceId,
 80→      path: null,
 81→    });
 82→
 83→    // Shared helper — updates all active-file state + store in one place.
 84→    const setActiveFilePath = useCallback((path: string | null) => {
 85→      const currentWorkspaceId = workspaceIdRef.current;
 86→      const prev = activeFileRef.current;
 87→      if (prev.workspaceId === currentWorkspaceId && prev.path === path) return;
 88→      activeFileRef.current = { workspaceId: currentWorkspaceId, path };
 89→      setActiveFile(path);
 90→      onActiveFileChangeRef.current?.(path);
 91→      workspaceLayoutActions.setSelectedFilePath(currentWorkspaceId, path);
 92→    }, []);
 93→
 94→    useEffect(() => {
 95→      const container = scrollContainerRef.current;
 96→      if (!container) return;
 97→
 98→      let rafId = 0;
 99→
100→      const updateActiveFile = () => {
101→        rafId = 0;
102→        const changes = fileChangesRef.current;
103→        if (changes.length === 0) return;
104→
105→        const containerRect = container.getBoundingClientRect();
106→        // Threshold: a section is "active" if its top is within the top third
107→        // of the scroll container. This feels natural — the file you're reading
108→        // is the one near the top, not the one partially entering at the bottom.
109→        const threshold = containerRect.top + containerRect.height * 0.33;
110→
111→        let best: string | null = null;
112→
113→        for (const fc of changes) {
114→          const path = fc.file || fc.file_path || "";
115→          const el = sectionRefsMap.current.get(path);
116→          if (!el) continue;
117→
118→          const rect = el.getBoundingClientRect();
119→          // Section is visible if its bottom is below container top AND its top
120→          // is above the threshold line.
121→          if (rect.bottom > containerRect.top && rect.top <= threshold) {
122→            best = path;
123→          }
124→        }
125→
126→        // Fallback: if nothing passes the threshold (scrolled to very bottom),
127→        // pick the last section that's at least partially visible.
128→        if (best === null) {
129→          for (let i = changes.length - 1; i >= 0; i--) {
130→            const path = changes[i].file || changes[i].file_path || "";
