        </div>
      ) : compact ? (
        <AllFilesDiffViewer
          ref={diffViewerRef}
          workspaceId={workspace.id}
          fileChanges={filteredFileChanges}
          hideHeader
        />
      ) : (
        <div className="flex min-h-0 flex-1">
          <AllFilesDiffViewer
