            workspaceId={workspace.id}
            fileChanges={filteredFileChanges}
            hideHeader
            className="min-w-0 flex-1"
          />
          <FileChangeMinimap
            fileChanges={filteredFileChanges}
            selectedFile={selectedFilePath ?? null}
            onFileClick={handleFileClick}
          />
        </div>
      )}
    </div>
  );
}

