  1→/**
  2→ * Changes View — Self-contained diff viewer for the Changes content tab.
  3→ *
  4→ * Shows an infinite-scroll diff viewer (left) + changed files tree (right)
  5→ * with a filter dropdown (All Changes / Uncommitted / Last Turn) and
  6→ * a "Review Changes" button in the header bar.
  7→ *
  8→ * Fetches its own file change data — the parent just provides workspace + context.
  9→ */
 10→
 11→import { useRef, useMemo, useCallback, useState } from "react";
 12→import { GitBranch, SlidersHorizontal, ChevronDown, Check, ScanText } from "lucide-react";
 13→import {
 14→  DropdownMenu,
 15→  DropdownMenuTrigger,
 16→  DropdownMenuContent,
 17→  DropdownMenuItem,
 18→} from "@/components/ui/dropdown-menu";
 19→import { ResizablePanelGroup, ResizablePanel, ResizableHandle } from "@/components/ui/resizable";
 20→import { cn } from "@/shared/lib/utils";
 21→import { useWorkspaceLayout } from "../hooks/useWorkspaceLayout";
 22→import { useFileChanges } from "../api/workspace.queries";
 23→import { AllFilesDiffViewer, type AllFilesDiffViewerRef } from "./AllFilesDiffViewer";
 24→import { DiffFilesTree } from "./DiffFilesTree";
 25→import {
 26→  CHANGES_FILTER_OPTIONS,
 27→  changesFilterLabel,
 28→  type ChangesFilter,
 29→} from "../lib/changesFilter";
 30→import type { Workspace } from "@/shared/types";
 31→
 32→interface ChangesViewProps {
 33→  workspace: Workspace;
 34→  /** Whether file watcher is active — disables polling in useFileChanges */
 35→  isWatched?: boolean;
 36→  /** Callback to insert a code review prompt into the chat input */
 37→  onReview?: () => void;
 38→  /** Single-column layout without file tree side panel (used on mobile) */
 39→  compact?: boolean;
 40→}
 41→
 42→export function ChangesView({ workspace, isWatched = false, onReview, compact }: ChangesViewProps) {
 43→  const { selectedFilePath } = useWorkspaceLayout(workspace.id);
 44→  const diffViewerRef = useRef<AllFilesDiffViewerRef>(null);
 45→  const [changesFilter, setChangesFilter] = useState<ChangesFilter>("all-changes");
 46→
 47→  const isReady = workspace.state === "ready";
 48→
 49→  // Fetch file change data
 50→  const { data: fileChangesData } = useFileChanges(
 51→    isReady ? workspace.id : null,
 52→    workspace.session_status,
 53→    isWatched,
 54→    workspace.state
 55→  );
 56→  const fileChanges = useMemo(() => fileChangesData?.files ?? [], [fileChangesData]);
 57→
 58→  // TODO: Wire up uncommitted/last-turn filters when backend endpoints exist.
 59→  // For now, changesFilter is always "all-changes" (other options are commented out
 60→  // in CHANGES_FILTER_OPTIONS). When adding new filters, fetch the extra data here
 61→  // and use a match() to select the active list.
 62→  const filteredFileChanges = fileChanges;
 63→
 64→  // Scroll the diff viewer to the clicked file
 65→  const handleFileClick = useCallback((path: string) => {
 66→    diffViewerRef.current?.scrollToFile(path);
 67→  }, []);
 68→
 69→  const activeFilterLabel = changesFilterLabel(changesFilter);
 70→
 71→  return (
 72→    <div className="flex h-full flex-col overflow-hidden">
 73→      {/* Header — filter dropdown (left) + review button (right) */}
 74→      <div className="border-border-subtle flex h-10 flex-shrink-0 items-center justify-between border-b px-4">
 75→        <DropdownMenu>
 76→          <DropdownMenuTrigger asChild>
 77→            <button
 78→              type="button"
 79→              className="text-text-muted hover:text-text-secondary ease flex items-center gap-1 rounded-lg px-1.5 py-1 text-sm transition-colors duration-200"
 80→            >
 81→              <SlidersHorizontal className="h-[11px] w-[11px]" />
 82→              <span>{activeFilterLabel}</span>
 83→              <ChevronDown className="h-[10px] w-[10px]" />
 84→            </button>
 85→          </DropdownMenuTrigger>
 86→          <DropdownMenuContent align="start" className="min-w-[140px]">
 87→            {CHANGES_FILTER_OPTIONS.map(([value, label]) => (
 88→              <DropdownMenuItem
 89→                key={value}
 90→                onClick={() => setChangesFilter(value)}
 91→                className="gap-2 text-xs"
 92→              >
 93→                <Check
 94→                  className={cn("h-3 w-3", changesFilter === value ? "opacity-100" : "opacity-0")}
 95→                />
 96→                {label}
 97→              </DropdownMenuItem>
 98→            ))}
 99→          </DropdownMenuContent>
100→        </DropdownMenu>
101→
102→        {onReview && filteredFileChanges.length > 0 && (
103→          <button
104→            type="button"
105→            onClick={onReview}
106→            className="bg-primary/8 hover:bg-primary/14 text-primary ease flex h-7 items-center gap-1.5 rounded-lg px-2.5 text-xs font-medium transition-colors duration-200"
107→          >
108→            <ScanText className="h-3 w-3" />
109→            <span>Review Changes</span>
110→            <span className="text-primary/60 ml-0.5 text-[10px] font-normal">
111→              {filteredFileChanges.length}
112→            </span>
113→          </button>
114→        )}
115→      </div>
116→
117→      {/* Content area */}
118→      {filteredFileChanges.length === 0 ? (
119→        <div className="flex flex-1 flex-col items-center justify-center gap-3">
120→          <div className="bg-bg-muted/30 flex h-10 w-10 items-center justify-center rounded-xl">
121→            <GitBranch className="text-text-muted/50 h-5 w-5" aria-hidden="true" />
122→          </div>
123→          <p className="text-text-muted/60 text-xs">No file changes yet</p>
124→          <p className="text-text-muted/40 max-w-[200px] text-center text-[11px]">
125→            Changes will appear here as the agent modifies files
126→          </p>
127→        </div>
128→      ) : compact ? (
129→        <AllFilesDiffViewer
130→          ref={diffViewerRef}
131→          workspaceId={workspace.id}
132→          fileChanges={filteredFileChanges}
133→          hideHeader
134→        />
135→      ) : (
136→        <ResizablePanelGroup direction="horizontal" className="min-h-0 flex-1">
137→          <ResizablePanel defaultSize={75} minSize={30}>
138→            <AllFilesDiffViewer
139→              ref={diffViewerRef}
140→              workspaceId={workspace.id}
141→              fileChanges={filteredFileChanges}
142→              hideHeader
143→            />
144→          </ResizablePanel>
145→
146→          <ResizableHandle />
147→
148→          <ResizablePanel defaultSize={25} minSize={15}>
149→            <DiffFilesTree
150→              fileChanges={filteredFileChanges}
151→              selectedFile={selectedFilePath ?? null}
152→              onFileClick={handleFileClick}
153→            />
154→          </ResizablePanel>
155→        </ResizablePanelGroup>
156→      )}
157→    </div>
158→  );
159→}
