37→      <ResizablePanel defaultSize={75} minSize={30}>
38→        {selectedFilePath ? (
39→          <FileViewer workspaceId={workspace.id} filePath={selectedFilePath.replace(/^\/+/, "")} />
40→        ) : (
41→          <div className="flex h-full flex-col items-center justify-center gap-3">
42→            <div className="bg-bg-muted/30 flex h-10 w-10 items-center justify-center rounded-xl">
43→              <FileText className="text-text-muted/50 h-5 w-5" aria-hidden="true" />
44→            </div>
45→            <p className="text-text-muted/60 text-xs">Select a file to preview</p>
46→          </div>
47→        )}
48→      </ResizablePanel>
49→
50→      <ResizableHandle />
51→
52→      <ResizablePanel defaultSize={25} minSize={15}>
53→        <FileBrowserPanel
54→          selectedWorkspace={workspace}
55→          fileChanges={fileChanges}
56→          selectedFilePath={selectedFilePath}
57→          onFileClick={setSelectedFilePath}
58→          filterMode="all"
59→          hideTabToggle
60→        />
61→      </ResizablePanel>
62→    </ResizablePanelGroup>
63→  );
64→}
