  1→/**
  2→ * AllFilesDiffViewer — Scrollable container for all changed files' diffs.
  3→ *
  4→ * Renders each changed file as an AllDiffFileSection with lazy loading.
  5→ * Exposes `scrollToFile(path)` via ref for bidirectional sync with the file tree.
  6→ * Tracks which file is currently visible and reports it via `onActiveFileChange`.
  7→ *
  8→ * Scroll-spy: centralized scroll listener finds the topmost visible section
  9→ * and syncs active file state to the sidebar tree.
 10→ *
 11→ * Performance: IntersectionObserver lazy loading per section, React.memo,
 12→ * rAF-throttled scroll spy.
 13→ */
 14→
 15→import { forwardRef, useImperativeHandle, useRef, useCallback, useState, useEffect } from "react";
 16→import { ChevronsUpDown } from "lucide-react";
 17→import { AllDiffFileSection } from "./AllDiffFileSection";
 18→import { workspaceLayoutActions } from "../store";
 19→import type { FileChange } from "@/shared/types";
 20→
 21→export interface AllFilesDiffViewerRef {
 22→  scrollToFile: (path: string) => void;
 23→}
 24→
 25→interface AllFilesDiffViewerProps {
 26→  workspaceId: string;
 27→  fileChanges: FileChange[];
 28→  /** Hide the header bar (file count, collapse/expand). Used when
 29→   *  the viewer is embedded inside ChangesView which has its own chrome. */
 30→  hideHeader?: boolean;
 31→  onActiveFileChange?: (filePath: string | null) => void;
 32→  /** File to scroll to on mount (one-shot) */
 33→  initialScrollTarget?: string;
 34→}
 35→
 36→export const AllFilesDiffViewer = forwardRef<AllFilesDiffViewerRef, AllFilesDiffViewerProps>(
 37→  function AllFilesDiffViewer(
 38→    { workspaceId, fileChanges, hideHeader, onActiveFileChange, initialScrollTarget },
 39→    ref
 40→  ) {
 41→    const sectionRefsMap = useRef(new Map<string, HTMLDivElement>());
 42→    const scrollContainerRef = useRef<HTMLDivElement>(null);
 43→    const [activeFile, setActiveFile] = useState<string | null>(null);
 44→    // Key counter for collapse-all/expand-all — incrementing remounts all sections expanded
 45→    const [expandStateKey, setExpandStateKey] = useState(0);
 46→
 47→    // Ref-based stable wrappers for props that change identity on refetch.
 48→    const workspaceIdRef = useRef(workspaceId);
 49→    const fileChangesRef = useRef(fileChanges);
 50→    const onActiveFileChangeRef = useRef(onActiveFileChange);
 51→
 52→    useEffect(() => {
 53→      workspaceIdRef.current = workspaceId;
 54→      fileChangesRef.current = fileChanges;
 55→      onActiveFileChangeRef.current = onActiveFileChange;
 56→    });
 57→
 58→    // Clear ref maps on unmount to prevent stale entries
 59→    useEffect(() => {
 60→      return () => {
 61→        sectionRefsMap.current.clear();
 62→      };
 63→    }, []);
 64→
 65→    // Resolve a file path to its DOM element — ref map first, DOM query fallback.
 66→    const resolveSection = useCallback((path: string): HTMLElement | null => {
 67→      const el = sectionRefsMap.current.get(path);
 68→      if (el) return el;
 69→      return (
 70→        scrollContainerRef.current?.querySelector(`[data-diff-path="${CSS.escape(path)}"]`) ?? null
 71→      );
 72→    }, []);
 73→
 74→    // --- Scroll-spy: centralized scroll event listener ---
 75→    // Finds the topmost section whose top edge is at or above the container's
 76→    // vertical midpoint. More reliable than distributed IntersectionObservers
 77→    // in memoized children with content-visibility: auto.
 78→    const activeFileRef = useRef<{ workspaceId: string; path: string | null }>({
 79→      workspaceId,
 80→      path: null,
 81→    });
 82→
 83→    // Shared helper — updates all active-file state + store in one place.
 84→    const setActiveFilePath = useCallback((path: string | null) => {
 85→      const currentWorkspaceId = workspaceIdRef.current;
 86→      const prev = activeFileRef.current;
 87→      if (prev.workspaceId === currentWorkspaceId && prev.path === path) return;
 88→      activeFileRef.current = { workspaceId: currentWorkspaceId, path };
 89→      setActiveFile(path);
 90→      onActiveFileChangeRef.current?.(path);
 91→      workspaceLayoutActions.setSelectedFilePath(currentWorkspaceId, path);
 92→    }, []);
 93→
 94→    useEffect(() => {
 95→      const container = scrollContainerRef.current;
 96→      if (!container) return;
 97→
 98→      let rafId = 0;
 99→
100→      const updateActiveFile = () => {
101→        rafId = 0;
102→        const changes = fileChangesRef.current;
103→        if (changes.length === 0) return;
104→
105→        const containerRect = container.getBoundingClientRect();
106→        // Threshold: a section is "active" if its top is within the top third
107→        // of the scroll container. This feels natural — the file you're reading
108→        // is the one near the top, not the one partially entering at the bottom.
109→        const threshold = containerRect.top + containerRect.height * 0.33;
110→
111→        let best: string | null = null;
112→
113→        for (const fc of changes) {
114→          const path = fc.file || fc.file_path || "";
115→          const el = sectionRefsMap.current.get(path);
116→          if (!el) continue;
117→
118→          const rect = el.getBoundingClientRect();
119→          // Section is visible if its bottom is below container top AND its top
120→          // is above the threshold line.
121→          if (rect.bottom > containerRect.top && rect.top <= threshold) {
122→            best = path;
123→          }
124→        }
125→
126→        // Fallback: if nothing passes the threshold (scrolled to very bottom),
127→        // pick the last section that's at least partially visible.
128→        if (best === null) {
129→          for (let i = changes.length - 1; i >= 0; i--) {
130→            const path = changes[i].file || changes[i].file_path || "";
131→            const el = sectionRefsMap.current.get(path);
132→            if (!el) continue;
133→            const rect = el.getBoundingClientRect();
134→            if (rect.top < containerRect.bottom && rect.bottom > containerRect.top) {
135→              best = path;
136→              break;
137→            }
138→          }
139→        }
140→
141→        setActiveFilePath(best);
142→      };
143→
144→      const onScroll = () => {
145→        if (rafId === 0) {
146→          rafId = requestAnimationFrame(updateActiveFile);
147→        }
148→      };
149→
150→      container.addEventListener("scroll", onScroll, { passive: true });
151→
152→      // Fire once on mount to set the initial active file
153→      requestAnimationFrame(updateActiveFile);
154→
155→      return () => {
156→        container.removeEventListener("scroll", onScroll);
157→        if (rafId !== 0) cancelAnimationFrame(rafId);
158→      };
159→    }, []); // Stable — reads fileChanges via ref; section registration uses callback refs
160→
161→    // One-shot scroll to initial target after sections mount and register refs
162→    useEffect(() => {
163→      if (!initialScrollTarget) return;
164→      const raf = requestAnimationFrame(() => {
165→        const target = resolveSection(initialScrollTarget);
166→        if (!target) return;
167→        setActiveFilePath(initialScrollTarget);
168→        target.scrollIntoView({
169→          behavior: "auto",
170→          block: "start",
171→        });
172→      });
173→      return () => cancelAnimationFrame(raf);
174→    }, [initialScrollTarget, workspaceId, resolveSection, setActiveFilePath]);
175→
176→    // Expose scrollToFile to parent — immediately updates active file
177→    // so the tree highlight changes without waiting for the scroll event.
178→    useImperativeHandle(
179→      ref,
180→      () => ({
181→        scrollToFile(path: string) {
182→          setActiveFilePath(path);
183→          const el = resolveSection(path);
184→          if (el) {
185→            el.scrollIntoView({ behavior: "smooth", block: "start" });
186→          }
187→        },
188→      }),
189→      [workspaceId, resolveSection]
190→    );
191→
192→    // Section ref callback — populates the ref map
193→    const sectionRefCallback = useCallback((filePath: string, el: HTMLDivElement | null) => {
194→      if (el) {
195→        sectionRefsMap.current.set(filePath, el);
196→      } else {
197→        sectionRefsMap.current.delete(filePath);
198→      }
199→    }, []);
200→
201→    const handleCollapseExpandAll = useCallback(() => {
202→      setExpandStateKey((prev) => prev + 1);
203→    }, []);
204→
205→    return (
206→      <div className="flex h-full flex-col overflow-hidden">
207→        {/* Header bar — hidden when embedded in ChangesView */}
208→        {!hideHeader && (
209→          <div className="bg-muted/20 border-border/40 flex h-8 flex-shrink-0 items-center justify-between border-b px-3">
210→            <span className="text-muted-foreground/70 text-xs tabular-nums">
211→              {fileChanges.length} {fileChanges.length === 1 ? "file" : "files"} changed
212→            </span>
213→            <button
214→              type="button"
215→              onClick={handleCollapseExpandAll}
216→              className="text-muted-foreground hover:text-foreground hover:bg-muted/50 ease flex h-5 w-5 items-center justify-center rounded-md transition-colors duration-200"
217→              title="Reset expand/collapse"
218→            >
219→              <ChevronsUpDown className="h-3.5 w-3.5" />
220→            </button>
221→          </div>
222→        )}
223→
224→        {/* Scrollable file sections */}
225→        <div
226→          ref={scrollContainerRef}
227→          className="divide-border/40 flex flex-1 flex-col divide-y overflow-y-auto pb-3"
228→        >
229→          {fileChanges.map((fc) => {
230→            const path = fc.file || fc.file_path || "";
231→            return (
232→              <AllDiffFileSection
233→                key={path}
234→                workspaceId={workspaceId}
235→                fileChange={fc}
236→                isActive={activeFile === path}
237→                sectionRef={sectionRefCallback}
238→                expandStateKey={expandStateKey}
239→              />
240→            );
241→          })}
242→        </div>
243→      </div>
244→    );
245→  }
246→);
247→

  1→/**
  2→ * AllDiffFileSection — Memoized per-file section for the all-diffs view.
  3→ *
  4→ * Uses IntersectionObserver with 600px rootMargin for lazy-loading diff data
  5→ * when the section approaches the viewport.
  6→ *
  7→ * Scroll-spy (active file tracking) is handled by the parent AllFilesDiffViewer
  8→ * via a centralized scroll event listener.
  9→ */
 10→
 11→import { useState, useRef, useEffect, useCallback, memo } from "react";
 12→import { ChevronDown, ChevronRight } from "lucide-react";
 13→import { cn } from "@/shared/lib/utils";
 14→import { DiffViewer } from "./DiffViewer";
 15→import { useFileDiff } from "../api/workspace.queries";
 16→import type { FileChange } from "@/shared/types";
 17→
 18→interface AllDiffFileSectionProps {
 19→  workspaceId: string;
 20→  fileChange: FileChange;
 21→  isActive: boolean;
 22→  sectionRef: (filePath: string, el: HTMLDivElement | null) => void;
 23→  /** Key counter — when it changes, section resets to expanded state */
 24→  expandStateKey: number;
 25→}
 26→
 27→function AllDiffFileSectionInner({
 28→  workspaceId,
 29→  fileChange,
 30→  isActive,
 31→  sectionRef,
 32→  expandStateKey,
 33→}: AllDiffFileSectionProps) {
 34→  const filePath = fileChange.file || fileChange.file_path || "";
 35→  const [collapsedState, setCollapsedState] = useState({
 36→    value: false,
 37→    expandStateKey,
 38→  });
 39→  const [isNearVisible, setIsNearVisible] = useState(false);
 40→  const containerRef = useRef<HTMLDivElement | null>(null);
 41→
 42→  // Collapse state resets to expanded whenever expandStateKey changes,
 43→  // without requiring a state update from an effect.
 44→  const collapsed = collapsedState.expandStateKey === expandStateKey ? collapsedState.value : false;
 45→
 46→  // Register ref for scroll-to-file and parent scroll-spy
 47→  const refCallback = useCallback(
 48→    (el: HTMLDivElement | null) => {
 49→      containerRef.current = el;
 50→      sectionRef(filePath, el);
 51→    },
 52→    [filePath, sectionRef]
 53→  );
 54→
 55→  // IntersectionObserver: lazy loading (600px rootMargin)
 56→  useEffect(() => {
 57→    const el = containerRef.current;
 58→    if (!el) return;
 59→
 60→    const observer = new IntersectionObserver(
 61→      ([entry]) => {
 62→        if (entry.isIntersecting) {
 63→          setIsNearVisible(true);
 64→          observer.disconnect();
 65→        }
 66→      },
 67→      { rootMargin: "600px" }
 68→    );
 69→    observer.observe(el);
 70→    return () => observer.disconnect();
 71→  }, []);
 72→
 73→  // Fetch diff only when near-visible
 74→  const { data, isLoading, error } = useFileDiff(
 75→    isNearVisible ? workspaceId : null,
 76→    isNearVisible ? filePath : null
 77→  );
 78→
 79→  return (
 80→    <div ref={refCallback} data-diff-path={filePath} className="overflow-clip">
 81→      {/* Sticky file header — two sibling buttons to avoid nesting interactive elements */}
 82→      <div
 83→        className={`sticky top-0 z-[5] flex min-h-[44px] w-full items-center gap-2 px-3 py-1.5 transition-colors duration-200 ease-[cubic-bezier(.165,.84,.44,1)] ${
 84→          isActive
 85→            ? "bg-muted"
 86→            : collapsed
 87→              ? "bg-muted/15 hover:bg-muted/30"
 88→              : "hover:bg-muted bg-[var(--bg-elevated)]"
 89→        }`}
 90→      >
 91→        {/* Collapse toggle — covers chevron, path, and stats */}
 92→        <button
 93→          type="button"
 94→          onClick={() =>
 95→            setCollapsedState((prev) => ({
 96→              value: prev.expandStateKey === expandStateKey ? !prev.value : true,
 97→              expandStateKey,
 98→            }))
 99→          }
100→          className="flex min-w-0 flex-1 items-center gap-2 text-left"
101→        >
102→          {collapsed ? (
103→            <ChevronRight className="text-muted-foreground/60 h-3.5 w-3.5 flex-shrink-0" />
104→          ) : (
105→            <ChevronDown className="text-muted-foreground/60 h-3.5 w-3.5 flex-shrink-0" />
106→          )}
107→
108→          <span
109→            className={cn(
110→              "min-w-0 flex-1 truncate text-sm font-medium",
111→              collapsed && "text-muted-foreground/70"
112→            )}
113→          >
114→            {filePath}
115→          </span>
116→
117→          {/* +N / -N stats */}
118→          <span className="flex flex-shrink-0 items-center gap-1.5 text-sm tabular-nums">
119→            {fileChange.additions > 0 && (
120→              <span className="text-success/80">+{fileChange.additions}</span>
121→            )}
122→            {fileChange.deletions > 0 && (
123→              <span className="text-destructive/80">-{fileChange.deletions}</span>
124→            )}
125→          </span>
126→        </button>
127→      </div>
128→
129→      {/* Diff content — hidden when collapsed */}
130→      {!collapsed && (
131→        <DiffViewer
132→          filePath={filePath}
133→          diff={data?.diff ?? ""}
134→          oldContent={data?.oldContent ?? null}
135→          newContent={data?.newContent ?? null}
136→          isLoading={isNearVisible ? isLoading : true}
137→          error={error?.message}
138→          embedded
139→          workspaceId={workspaceId}
140→        />
141→      )}
142→    </div>
143→  );
144→}
145→
146→export const AllDiffFileSection = memo(AllDiffFileSectionInner, (prev, next) => {
147→  const prevPath = prev.fileChange.file || prev.fileChange.file_path || "";
148→  const nextPath = next.fileChange.file || next.fileChange.file_path || "";
149→  return (
150→    prevPath === nextPath &&
151→    prev.fileChange.additions === next.fileChange.additions &&
152→    prev.fileChange.deletions === next.fileChange.deletions &&
153→    prev.isActive === next.isActive &&
154→    prev.workspaceId === next.workspaceId &&
155→    prev.expandStateKey === next.expandStateKey
156→  );
157→});
