 67→
 68→/**
 69→ * Overlay change data (additions/deletions) from git diff onto the IPC-scanned tree.
 70→ * Builds a path→change lookup and walks the tree to decorate matching files.
 71→ */
 72→function enrichTreeWithChanges(nodes: FileTreeNode[], changes: FileChange[]): FileTreeNode[] {
 73→  if (changes.length === 0) return nodes;
 74→
 75→  const changeMap = new Map<string, FileChange>();
 76→  for (const c of changes) {
 77→    const path = c.file || c.file_path || "";
 78→    if (path) changeMap.set(path, c);
 79→  }
 80→
 81→  function walk(nodeList: FileTreeNode[]): FileTreeNode[] {
 82→    return nodeList.map((node) => {
 83→      if (node.type === "file") {
 84→        const change = changeMap.get(node.path);
 85→        if (change) {
 86→          const status =
 87→            change.additions > 0 && change.deletions === 0
 88→              ? "added"
 89→              : change.deletions > 0 && change.additions === 0
 90→                ? "deleted"
 91→                : "modified";
 92→          return {
 93→            ...node,
 94→            additions: change.additions,
 95→            deletions: change.deletions,
 96→            change_status: status as "added" | "modified" | "deleted",
 97→            committed: change.committed,
 98→          };
 99→        }
100→        return node;
101→      }
102→      // Directory: recurse into children
103→      if (node.children) {
104→        return { ...node, children: walk(node.children) };
105→      }
106→      return node;
107→    });
108→  }
109→
110→  return walk(nodes);
111→}
112→
113→/** Filter tree to only files with actual diff changes (and their ancestor directories).
114→ *
115→ * Uses `change_status` (set by enrichTreeWithChanges from diff query results) only.
116→ * Does NOT use `git_status` (from the file scanner) because libgit2's status API
117→ * produces phantom statuses in git worktrees, causing clean files to appear as changed.
118→ */
119→function filterToChangedOnly(nodes: FileTreeNode[]): FileTreeNode[] {
120→  return nodes.reduce((acc, node) => {
121→    if (node.type === "file") {
122→      if (node.change_status) {
123→        acc.push(node);
124→      }
125→    } else if (node.children) {
126→      const filtered = filterToChangedOnly(node.children);
127→      if (filtered.length > 0) {
128→        acc.push({ ...node, children: filtered });
129→      }
130→    }
131→    return acc;
132→  }, [] as FileTreeNode[]);
133→}
134→
135→/** Filter tree to only files matching a specific change set */
136→function filterToChangeSet(nodes: FileTreeNode[], allowedPaths: Set<string>): FileTreeNode[] {
137→  return nodes.reduce((acc, node) => {
138→    if (node.type === "file") {
139→      if (allowedPaths.has(node.path)) {
140→        acc.push(node);
141→      }
142→    } else if (node.children) {
143→      const filtered = filterToChangeSet(node.children, allowedPaths);
144→      if (filtered.length > 0) {
145→        acc.push({ ...node, children: filtered });
146→      }
147→    }
148→    return acc;
149→  }, [] as FileTreeNode[]);
150→}
151→
152→/** Filter tree by search query (case-insensitive name match, preserving ancestor dirs) */
153→function filterTreeBySearch(nodes: FileTreeNode[], query: string): FileTreeNode[] {
154→  const lower = query.toLowerCase();
155→  return nodes.reduce((acc, node) => {
156→    if (node.type === "file") {
157→      if (node.name.toLowerCase().includes(lower) || node.path.toLowerCase().includes(lower)) {
158→        acc.push(node);
159→      }
160→    } else if (node.children) {
161→      // Check if directory name matches — if so, include all children
162→      if (node.name.toLowerCase().includes(lower)) {
163→        acc.push(node);
164→      } else {
165→        const filtered = filterTreeBySearch(node.children, query);
166→        if (filtered.length > 0) {
167→          acc.push({ ...node, children: filtered });
168→        }
169→      }
170→    }
171→    return acc;
172→  }, [] as FileTreeNode[]);
173→}
174→
175→/** Count changed files in tree (only diff-confirmed changes, not scanner git_status) */
176→function countChangedFiles(nodes: FileTreeNode[]): number {
177→  let count = 0;
178→  for (const node of nodes) {
179→    if (node.type === "file" && node.change_status) count++;
180→    if (node.children) count += countChangedFiles(node.children);
181→  }
182→  return count;
183→}
184→
185→/** Build a Set of file paths from a FileChange array */
186→function buildPathSet(changes: FileChange[]): Set<string> {
187→  const set = new Set<string>();
188→  for (const c of changes) {
189→    const p = c.file || c.file_path || "";
190→    if (p) set.add(p);
191→  }
192→  return set;
193→}
