195→export function FileBrowserPanel({
196→  selectedWorkspace,
197→  fileChanges = EMPTY_FILE_CHANGES,
198→  uncommittedFiles,
199→  lastTurnFiles,
200→  fileChangesTruncated,
201→  fileChangesTotalCount,
202→  selectedFilePath,
203→  onFileClick: onFileClickProp,
204→  headerSlot,
205→  filterMode: controlledFilterMode,
206→  onFilterModeChange,
207→  hideTabToggle = false,
208→}: FileBrowserPanelProps) {
209→  // Controlled when parent provides filterMode, uncontrolled fallback otherwise.
210→  const [localFilterMode, setLocalFilterMode] = useState<FilterMode>("changes");
211→  const filterMode = controlledFilterMode ?? localFilterMode;
212→  const setFilterMode = onFilterModeChange ?? setLocalFilterMode;
213→  const [changesFilter, setChangesFilter] = useState<ChangesFilter>("all-changes");
214→  const [searchQuery, setSearchQuery] = useState("");
215→  const searchInputRef = useRef<HTMLInputElement>(null);
216→
217→  const workspaceId = selectedWorkspace?.id ?? null;
218→  const { data, isLoading, error, refetch } = useFiles(workspaceId);
219→
220→  const handleFileClick = (path: string) => {
221→    onFileClickProp?.(path);
222→  };
223→
224→  const handleRefresh = async () => {
225→    if (workspaceId) {
226→      await invalidateFileCache(workspaceId);
227→      refetch();
228→    }
229→  };
230→
231→  // Focus search input when it appears
232→  useEffect(() => {
233→    if (filterMode === "all" && searchInputRef.current) {
234→      searchInputRef.current.focus();
235→    }
236→  }, [filterMode]);
237→
238→  // Clear search when switching away from All tab
239→  useEffect(() => {
240→    // eslint-disable-next-line react-hooks/set-state-in-effect -- intentional: clear search on filter change
241→    if (filterMode !== "all") setSearchQuery("");
242→  }, [filterMode]);
243→
244→  // Path sets for sub-filters
245→  const uncommittedPaths = useMemo(
246→    () => (uncommittedFiles ? buildPathSet(uncommittedFiles) : null),
247→    [uncommittedFiles]
248→  );
249→  const lastTurnPaths = useMemo(
250→    () => (lastTurnFiles ? buildPathSet(lastTurnFiles) : null),
251→    [lastTurnFiles]
252→  );
253→
254→  // Enrich tree with change data + committed flag
255→  const enrichedTree = useMemo(() => {
256→    if (!data) return [];
257→
258→    // Tag committed status: files NOT in uncommitted set are committed
259→    const taggedChanges = fileChanges.map((c) => {
260→      const path = c.file || c.file_path || "";
261→      const isUncommitted = uncommittedPaths ? uncommittedPaths.has(path) : undefined;
262→      return {
263→        ...c,
264→        committed: isUncommitted !== undefined ? !isUncommitted : undefined,
265→      };
266→    });
267→
268→    return enrichTreeWithChanges(data.files, taggedChanges);
269→  }, [data, fileChanges, uncommittedPaths]);
270→
271→  const changedCount = useMemo(() => countChangedFiles(enrichedTree), [enrichedTree]);
272→
273→  // Apply filter mode + sub-filter + search
274→  const filteredFiles = useMemo(() => {
275→    if (filterMode === "all") {
276→      // All files with optional search
277→      return searchQuery ? filterTreeBySearch(enrichedTree, searchQuery) : enrichedTree;
278→    }
279→
280→    // Changes mode — apply sub-filter
281→    const changedOnly = filterToChangedOnly(enrichedTree);
282→
283→    if (changesFilter === "uncommitted" && uncommittedPaths) {
284→      return filterToChangeSet(changedOnly, uncommittedPaths);
285→    }
286→    if (changesFilter === "last-turn" && lastTurnPaths) {
287→      return filterToChangeSet(changedOnly, lastTurnPaths);
288→    }
289→
290→    return changedOnly;
291→  }, [enrichedTree, filterMode, searchQuery, changesFilter, uncommittedPaths, lastTurnPaths]);
292→
293→  // Empty state — no workspace
294→  if (!selectedWorkspace) {
295→    return (
296→      <div className="flex h-full flex-col overflow-hidden">
297→        {headerSlot}
298→        <div className="animate-fade-in-up flex flex-1 flex-col items-center justify-center gap-3">
299→          <div className="bg-muted/30 flex h-10 w-10 items-center justify-center rounded-xl">
300→            <FileCode className="text-muted-foreground/50 h-5 w-5" aria-hidden="true" />
301→          </div>
302→          <p className="text-muted-foreground/60 text-xs">Select a workspace to view files</p>
303→        </div>
304→      </div>
305→    );
306→  }
307→
308→  // Loading state
309→  if (isLoading) {
310→    return (
311→      <div className="flex h-full flex-col overflow-hidden">
312→        {headerSlot}
313→        <div className="animate-fade-in flex flex-1 flex-col items-center justify-center gap-3">
314→          <Loader2 className="text-muted-foreground/50 h-5 w-5 animate-spin" />
315→          <p className="text-muted-foreground/60 text-xs">Scanning files...</p>
316→        </div>
317→      </div>
318→    );
319→  }
320→
321→  // Error state
322→  if (error) {
323→    return (
324→      <div className="flex h-full flex-col overflow-hidden">
325→        {headerSlot}
326→        <div className="animate-fade-in-up flex flex-1 flex-col items-center justify-center gap-3">
327→          <div className="bg-muted/30 flex h-10 w-10 items-center justify-center rounded-xl">
328→            <FolderOpen className="text-muted-foreground/50 h-5 w-5" aria-hidden="true" />
329→          </div>
330→          <p className="text-muted-foreground/60 text-xs">
331→            {error instanceof Error ? error.message : "Unable to load files"}
332→          </p>
333→        </div>
334→      </div>
335→    );
336→  }
337→
338→  return (
339→    <div className="flex h-full flex-col overflow-hidden">
340→      {headerSlot}
341→
342→      {/* Header: tab toggle (left) + filter dropdown (right) — hidden when parent manages tabs */}
343→      {!hideTabToggle && (
344→        <div className="flex h-9 flex-shrink-0 items-center justify-between px-3">
345→          {/* Tab toggle: Changes | All files */}
346→          <div className="flex items-center gap-0.5">
347→            <button
348→              onClick={() => setFilterMode("changes")}
349→              className={cn(
350→                "rounded-lg px-2 py-1 text-xs transition-colors duration-200 ease-[ease]",
351→                filterMode === "changes"
352→                  ? "bg-muted text-secondary-foreground font-medium"
353→                  : "text-muted-foreground hover:text-foreground"
354→              )}
355→            >
356→              Changes
357→            </button>
358→            <button
359→              onClick={() => setFilterMode("all")}
360→              className={cn(
361→                "rounded-lg px-2 py-1 text-xs transition-colors duration-200 ease-[ease]",
362→                filterMode === "all"
363→                  ? "bg-muted text-secondary-foreground font-medium"
364→                  : "text-muted-foreground hover:text-foreground"
365→              )}
366→            >
367→              All files
368→            </button>
369→          </div>
370→
371→          {/* Right-side actions — visible in Changes mode */}
372→          {filterMode === "changes" && (
373→            <div className="flex items-center gap-1">
374→              <DropdownMenu>
375→                <DropdownMenuTrigger asChild>
376→                  <button className="text-muted-foreground hover:text-foreground flex items-center gap-1 rounded-lg py-1 text-xs transition-colors duration-200 ease-[ease]">
377→                    <SlidersHorizontal className="h-[11px] w-[11px]" />
378→                    <span>{changesFilterLabel(changesFilter)}</span>
379→                    <ChevronDown className="h-[10px] w-[10px]" />
380→                  </button>
381→                </DropdownMenuTrigger>
382→                <DropdownMenuContent align="end" className="min-w-[140px]">
383→                  {CHANGES_FILTER_OPTIONS.map(([value, label]) => (
384→                    <DropdownMenuItem
385→                      key={value}
386→                      onClick={() => setChangesFilter(value)}
387→                      className="gap-2 text-xs"
388→                    >
389→                      <Check
390→                        className={cn(
391→                          "h-3 w-3",
392→                          changesFilter === value ? "opacity-100" : "opacity-0"
393→                        )}
394→                      />
395→                      {label}
396→                    </DropdownMenuItem>
397→                  ))}
398→                  <DropdownMenuSeparator />
399→                  <DropdownMenuItem onClick={handleRefresh} className="gap-2 text-xs">
400→                    <RefreshCw className="h-3 w-3" />
401→                    Refresh files
402→                  </DropdownMenuItem>
403→                </DropdownMenuContent>
404→              </DropdownMenu>
405→            </div>
406→          )}
407→        </div>
408→      )}
409→
410→      {/* Search bar — only for All files tab */}
411→      {filterMode === "all" && (
412→        <div className="border-border/30 flex items-center gap-1.5 border-b px-2 py-1">
413→          <Search className="text-muted-foreground/40 h-3 w-3 flex-shrink-0" />
414→          <input
415→            ref={searchInputRef}
416→            type="text"
417→            placeholder="Filter files..."
418→            value={searchQuery}
419→            onChange={(e) => setSearchQuery(e.target.value)}
420→            className="text-foreground placeholder:text-muted-foreground/40 h-5 min-w-0 flex-1 bg-transparent text-xs outline-none"
421→          />
422→          {searchQuery && (
423→            <button
424→              onClick={() => setSearchQuery("")}
425→              className="text-muted-foreground/40 hover:text-muted-foreground flex-shrink-0"
426→            >
427→              <X className="h-3 w-3" />
428→            </button>
429→          )}
430→        </div>
431→      )}
432→
433→      {/* Truncation warning — shown when diff has too many files */}
434→      {fileChangesTruncated && filterMode === "changes" && (
435→        <div className="border-border/30 bg-muted/20 border-b px-2.5 py-1.5">
436→          <p className="text-muted-foreground text-xs">
437→            Showing {fileChanges.length.toLocaleString()} of{" "}
438→            {(fileChangesTotalCount ?? 0).toLocaleString()} changed files
439→          </p>
440→        </div>
441→      )}
442→
443→      {/* File Tree */}
444→      <div className="flex-1 overflow-y-auto py-1">
445→        {filteredFiles.length > 0 ? (
446→          <FileTree
447→            key={filterMode}
448→            nodes={filteredFiles}
449→            selectedPath={selectedFilePath}
450→            onFileClick={handleFileClick}
451→            defaultExpanded={filterMode === "changes"}
452→          />
453→        ) : (
454→          <div className="animate-fade-in-up flex flex-col items-center justify-center gap-3 py-12">
455→            <div className="bg-muted/30 flex h-10 w-10 items-center justify-center rounded-xl">
456→              {filterMode === "changes" ? (
457→                <GitBranch className="text-muted-foreground/50 h-5 w-5" aria-hidden="true" />
458→              ) : (
459→                <FolderOpen className="text-muted-foreground/50 h-5 w-5" aria-hidden="true" />
460→              )}
461→            </div>
462→            <p className="text-muted-foreground/60 text-xs">
463→              {filterMode === "changes"
464→                ? "No file changes detected"
465→                : searchQuery
466→                  ? "No matching files"
467→                  : "No files found"}
468→            </p>
469→          </div>
470→        )}
471→      </div>
472→    </div>
473→  );
474→}
