170→/**
171→ * Fetch file changes for a workspace
172→ * Conditionally polls only when workspace is actively working.
173→ *
174→ * When `isWatched` is true (file watcher active via notify crate),
175→ * polling is disabled — cache invalidation comes from fs:changed events.
176→ * Falls back to 5s polling when not watched.
177→ *
178→ * IMPORTANT: Requires workspaceState === "ready" — same guard as useDiffStats.
179→ * See useDiffStats comment for the full explanation of the phantom diff race.
180→ */
181→export function useFileChanges(
182→  workspaceId: string | null,
183→  sessionStatus?: string | null,
184→  isWatched: boolean = false,
185→  workspaceState?: string | null
186→) {
187→  return useQuery({
188→    queryKey: queryKeys.workspaces.diffFiles(workspaceId || ""),
189→    queryFn: async () => {
190→      const result = await WorkspaceService.fetchDiffFiles(workspaceId!);
191→      return {
192→        files: result.files || [],
193→        truncated: result.truncated ?? false,
194→        totalCount: result.totalCount ?? result.files?.length ?? 0,
195→      };
196→    },
197→    enabled: !!workspaceId && workspaceState === "ready",
198→    staleTime: 30000,
199→    // Events handle invalidation when watched; fall back to polling otherwise
200→    refetchInterval: isWatched ? false : sessionStatus === "working" ? 5000 : false,
201→    refetchOnMount: "always",
202→    refetchOnWindowFocus: true,
203→  });
204→}
