 32→/** File icon + color by extension */
 33→function getFileIconConfig(filename: string): { icon: typeof File; color: string } {
 34→  const ext = filename.split(".").pop()?.toLowerCase() || "";
 35→
 36→  if (["ts", "tsx", "js", "jsx", "mjs", "cjs"].includes(ext))
 37→    return { icon: FileCode, color: "text-file-typescript" };
 38→  if (["rs", "toml"].includes(ext)) return { icon: FileCode, color: "text-file-rust" };
 39→  if (["json", "yaml", "yml", "xml"].includes(ext))
 40→    return { icon: FileJson, color: "text-file-data" };
 41→  if (["md", "mdx", "txt", "rst"].includes(ext)) return { icon: FileText, color: "text-file-docs" };
 42→  if (["css", "scss", "sass", "less"].includes(ext))
 43→    return { icon: FileCode, color: "text-file-styles" };
 44→  if (["html", "htm"].includes(ext)) return { icon: FileCode, color: "text-file-markup" };
 45→  if (["png", "jpg", "jpeg", "gif", "webp", "svg", "ico"].includes(ext))
 46→    return { icon: FileImage, color: "text-file-image" };
 47→  if (
 48→    ["env", "gitignore", "dockerignore", "editorconfig"].includes(ext) ||
 49→    filename.startsWith(".")
 50→  )
 51→    return { icon: FileType, color: "text-muted-foreground/50" };
 52→  return { icon: File, color: "text-muted-foreground/40" };
