 24→  workspaceId?: string;
 25→}
 26→
 27→/**
 28→ * DiffViewer - Git diff viewer powered by @pierre/diffs
 29→ *
 30→ * Renders unified diffs with syntax highlighting, word-level change detection,
 31→ * and hunk separators. Uses Shadow DOM for style isolation.
 32→ *
 33→ * Data flow: Backend returns raw diff + file contents → FileDiff parses and renders
 34→ */
 35→type CommentSide = "additions" | "deletions";
 36→
 37→interface DiffComment {
 38→  id: string;
 39→  lineNumber: number;
 40→  side: CommentSide;
 41→  text: string;
 42→  createdAt: string;
 43→}
 44→
 45→interface DiffCommentDraft {
 46→  lineNumber: number;
 47→  side: CommentSide;
 48→  text: string;
 49→}
 50→
 51→interface DiffCommentMeta {
 52→  id: string;
 53→  text: string;
 54→  createdAt?: string;
 55→  isDraft?: boolean;
 56→}
 57→
 58→export function DiffViewer({
 59→  filePath = "",
 60→  diff = "",
 61→  oldContent = null,
 62→  newContent = null,
 63→  isLoading = false,
 64→  error: errorProp = null,
 65→  onClose,
 66→  embedded = false,
 67→  workspaceId,
 68→}: DiffViewerProps) {
 69→  const [copied, setCopied] = useState(false);
 70→  const [comments, setComments] = useState<DiffComment[]>([]);
 71→  const [draftComment, setDraftComment] = useState<DiffCommentDraft | null>(null);
 72→  const [showAll, setShowAll] = useState(false);
 73→  const isMobile = useIsMobile();
 74→
 75→  // Mobile long-press tracking
 76→  const longPressTimerRef = useRef<ReturnType<typeof setTimeout>>();
 77→  const touchStartRef = useRef<{ x: number; y: number } | null>(null);
 78→  const lastEnteredLineRef = useRef<{ lineNumber: number; side: CommentSide } | null>(null);
 79→
 80→  const baseDiffOptions = useDiffOptions<DiffCommentMeta>();
 81→
 82→  const handleCopyDiff = async () => {
 83→    try {
 84→      await navigator.clipboard.writeText(diff);
 85→      setCopied(true);
 86→      setTimeout(() => setCopied(false), 2000);
 87→    } catch (error) {
 88→      console.error("Failed to copy diff:", error);
 89→    }
 90→  };
 91→
 92→  const diffIsEmpty = diff.trim().length === 0;
 93→  const hasContent = !isLoading && !errorProp && !diffIsEmpty;
 94→
 95→  const { displayFileDiff, canExpand } = useMemo(() => {
 96→    if (!diff.trim()) return { displayFileDiff: null, canExpand: false };
 97→    const fallbackName = filePath || "file";
 98→    const diffPaths = extractDiffPaths(diff);
 99→    const oldName = diffPaths.oldPath || fallbackName;
100→    const newName = diffPaths.newPath || fallbackName;
101→
102→    // Full-file parsing: when old + new content are available, use parseDiffFromFile
103→    // so the diff component has full context for expanding collapsed unchanged lines.
104→    const oldFile: FileContents | null =
105→      oldContent != null ? { name: oldName, contents: oldContent } : null;
106→    const newFile: FileContents | null =
107→      newContent != null ? { name: newName, contents: newContent } : null;
108→    if (oldFile && newFile) {
109→      try {
110→        const generated = parseDiffFromFile(oldFile, newFile);
111→        // Only use if it has hunks. Metadata-only changes (renames, chmod)
112→        // produce zero hunks — fall back to getSingularPatch for those.
113→        if (generated.hunks.length > 0) {
114→          return { displayFileDiff: applyDisplayNames(generated, fallbackName), canExpand: true };
115→        }
116→      } catch (error) {
117→        console.warn("Failed to generate full diff, falling back to patch diff", error);
118→      }
119→    }
