  1→/**
  2→ * FileChangeMinimap — Collapsed file tree that shows one colored line per changed file.
  3→ *
  4→ * Default state: thin vertical strip (~24px) on the right edge of the diff viewer.
  5→ * On hover: a floating panel slides in from the right showing the full DiffFilesTree.
  6→ *
  7→ * Each line's color encodes change type: green=added, yellow=modified, red=deleted.
  8→ * Clicking a line scrolls the diff viewer to that file.
  9→ *
 10→ * Hover-intent pattern: shared timeout between strip and panel prevents flicker
 11→ * when the mouse moves between them.
 12→ */
 13→
 14→import { useState, useRef, useCallback, useMemo } from "react";
 15→import { AnimatePresence, m } from "framer-motion";
 16→import { cn } from "@/shared/lib/utils";
 17→import { DiffFilesTree } from "./DiffFilesTree";
 18→import type { FileChange } from "@/shared/types";
 19→
 20→interface FileChangeMinimapProps {
 21→  fileChanges: FileChange[];
 22→  selectedFile: string | null;
 23→  onFileClick: (path: string) => void;
 24→}
 25→
 26→// --- Helpers ---
 27→
 28→function filePath(fc: FileChange): string {
 29→  return fc.file || fc.file_path || "";
 30→}
 31→
 32→type ChangeStatus = "added" | "modified" | "deleted";
 33→
 34→function getChangeStatus(fc: FileChange): ChangeStatus {
 35→  if (fc.additions > 0 && fc.deletions === 0) return "added";
 36→  if (fc.deletions > 0 && fc.additions === 0) return "deleted";
 37→  return "modified";
 38→}
 39→
 40→const STATUS_BG: Record<ChangeStatus, string> = {
 41→  added: "bg-success",
 42→  modified: "bg-warning",
 43→  deleted: "bg-destructive",
 44→};
 45→
 46→// --- Animation config ---
 47→
 48→const HOVER_ENTER_DELAY = 150; // ms before panel appears
 49→const HOVER_LEAVE_DELAY = 200; // ms before panel disappears
 50→
 51→const panelVariants = {
 52→  hidden: { opacity: 0, x: 4 },
 53→  visible: { opacity: 1, x: 0 },
 54→};
 55→
 56→const panelTransition = {
 57→  duration: 0.15,
 58→  ease: [0.165, 0.84, 0.44, 1], // ease-out-quart
 59→};
 60→
 61→// --- Component ---
 62→
 63→export function FileChangeMinimap({ fileChanges, selectedFile, onFileClick }: FileChangeMinimapProps) {
 64→  const [showPanel, setShowPanel] = useState(false);
 65→  const leaveTimeoutRef = useRef<ReturnType<typeof setTimeout>>();
 66→  const enterTimeoutRef = useRef<ReturnType<typeof setTimeout>>();
 67→
 68→  // Shared hover-intent: entering either strip or panel keeps the panel open
 69→  const handleMouseEnter = useCallback(() => {
 70→    clearTimeout(leaveTimeoutRef.current);
 71→    // Only delay on initial open — if already visible, keep it open immediately
 72→    if (!showPanel) {
 73→      enterTimeoutRef.current = setTimeout(() => setShowPanel(true), HOVER_ENTER_DELAY);
 74→    }
 75→  }, [showPanel]);
 76→
 77→  const handleMouseLeave = useCallback(() => {
 78→    clearTimeout(enterTimeoutRef.current);
 79→    leaveTimeoutRef.current = setTimeout(() => setShowPanel(false), HOVER_LEAVE_DELAY);
 80→  }, []);
 81→
 82→  // Memoize the line data to avoid re-computing on every render
 83→  const lines = useMemo(
 84→    () => fileChanges.map((fc) => ({ path: filePath(fc), status: getChangeStatus(fc) })),
 85→    [fileChanges]
 86→  );
 87→
 88→  return (
 89→    <div className="relative flex h-full flex-shrink-0">
 90→      {/* Strip — thin column of colored lines */}
 91→      <div
 92→        className="border-border/30 flex w-6 flex-col items-center gap-[3px] border-l py-3"
 93→        onMouseEnter={handleMouseEnter}
 94→        onMouseLeave={handleMouseLeave}
 95→      >
 96→        {lines.map((line) => (
 97→          <button
 98→            key={line.path}
 99→            type="button"
100→            onClick={() => onFileClick(line.path)}
101→            className={cn(
102→              "h-[2px] flex-shrink-0 rounded-full transition-all duration-150",
103→              STATUS_BG[line.status],
104→              selectedFile === line.path ? "w-3.5 opacity-100" : "w-2.5 opacity-60"
105→            )}
106→            aria-label={`${line.path} (${line.status})`}
107→          />
108→        ))}
109→      </div>
110→
111→      {/* Floating file tree panel — appears on hover */}
112→      <AnimatePresence>
113→        {showPanel && (
114→          <m.div
115→            initial="hidden"
116→            animate="visible"
117→            exit="hidden"
118→            variants={panelVariants}
119→            transition={panelTransition}
120→            className="border-border/40 bg-background absolute top-0 right-full bottom-0 z-50 w-60 border-l shadow-lg"
121→            onMouseEnter={handleMouseEnter}
122→            onMouseLeave={handleMouseLeave}
123→          >
124→            {/* Header */}
125→            <div className="border-border/30 flex h-8 items-center justify-between border-b px-3">
126→              <span className="text-text-muted text-xs">Files</span>
127→              <span className="text-text-muted/60 text-[10px] tabular-nums">
128→                {fileChanges.length}
129→              </span>
130→            </div>
131→
132→            {/* File tree — reused as-is */}
133→            <div className="h-[calc(100%-2rem)] overflow-hidden">
134→              <DiffFilesTree
135→                fileChanges={fileChanges}
136→                selectedFile={selectedFile}
137→                onFileClick={onFileClick}
138→              />
139→            </div>
140→          </m.div>
141→        )}
142→      </AnimatePresence>
143→    </div>
144→  );
145→}
