  1→/**
  2→ * AllFilesDiffViewer — Scrollable container for all changed files' diffs.
  3→ *
  4→ * Renders each changed file as an AllDiffFileSection with lazy loading.
  5→ * Exposes `scrollToFile(path)` via ref for bidirectional sync with the file tree.
  6→ * Tracks which file is currently visible and reports it via `onActiveFileChange`.
  7→ *
  8→ * Scroll-spy: centralized scroll listener finds the topmost visible section
  9→ * and syncs active file state to the sidebar tree.
 10→ *
 11→ * Performance: IntersectionObserver lazy loading per section, React.memo,
 12→ * rAF-throttled scroll spy.
 13→ */
 14→
 15→import { forwardRef, useImperativeHandle, useRef, useCallback, useState, useEffect } from "react";
 16→import { ChevronsUpDown } from "lucide-react";
 17→import { cn } from "@/shared/lib/utils";
 18→import { AllDiffFileSection } from "./AllDiffFileSection";
 19→import { workspaceLayoutActions } from "../store";
 20→import type { FileChange } from "@/shared/types";
 21→
 22→export interface AllFilesDiffViewerRef {
 23→  scrollToFile: (path: string) => void;
 24→}
 25→
 26→interface AllFilesDiffViewerProps {
 27→  workspaceId: string;
 28→  fileChanges: FileChange[];
 29→  /** Hide the header bar (file count, collapse/expand). Used when
 30→   *  the viewer is embedded inside ChangesView which has its own chrome. */
 31→  hideHeader?: boolean;
 32→  onActiveFileChange?: (filePath: string | null) => void;
 33→  /** File to scroll to on mount (one-shot) */
 34→  initialScrollTarget?: string;
 35→  /** Additional class names for the root container */
 36→  className?: string;
 37→}
 38→
 39→export const AllFilesDiffViewer = forwardRef<AllFilesDiffViewerRef, AllFilesDiffViewerProps>(
 40→  function AllFilesDiffViewer(
 41→    { workspaceId, fileChanges, hideHeader, onActiveFileChange, initialScrollTarget, className },
 42→    ref
 43→  ) {
 44→    const sectionRefsMap = useRef(new Map<string, HTMLDivElement>());
 45→    const scrollContainerRef = useRef<HTMLDivElement>(null);
 46→    const [activeFile, setActiveFile] = useState<string | null>(null);
 47→    // Key counter for collapse-all/expand-all — incrementing remounts all sections expanded
 48→    const [expandStateKey, setExpandStateKey] = useState(0);
 49→
 50→    // Ref-based stable wrappers for props that change identity on refetch.
 51→    const workspaceIdRef = useRef(workspaceId);
 52→    const fileChangesRef = useRef(fileChanges);
 53→    const onActiveFileChangeRef = useRef(onActiveFileChange);
 54→
 55→    useEffect(() => {
 56→      workspaceIdRef.current = workspaceId;
 57→      fileChangesRef.current = fileChanges;
 58→      onActiveFileChangeRef.current = onActiveFileChange;
 59→    });
 60→
 61→    // Clear ref maps on unmount to prevent stale entries
 62→    useEffect(() => {
 63→      return () => {
 64→        sectionRefsMap.current.clear();
 65→      };
 66→    }, []);
 67→
 68→    // Resolve a file path to its DOM element — ref map first, DOM query fallback.
 69→    const resolveSection = useCallback((path: string): HTMLElement | null => {
 70→      const el = sectionRefsMap.current.get(path);
 71→      if (el) return el;
 72→      return (
 73→        scrollContainerRef.current?.querySelector(`[data-diff-path="${CSS.escape(path)}"]`) ?? null
 74→      );
 75→    }, []);
 76→
 77→    // --- Scroll-spy: centralized scroll event listener ---
 78→    // Finds the topmost section whose top edge is at or above the container's
 79→    // vertical midpoint. More reliable than distributed IntersectionObservers
 80→    // in memoized children with content-visibility: auto.
 81→    const activeFileRef = useRef<{ workspaceId: string; path: string | null }>({
 82→      workspaceId,
 83→      path: null,
 84→    });
 85→
 86→    // Shared helper — updates all active-file state + store in one place.
 87→    const setActiveFilePath = useCallback((path: string | null) => {
 88→      const currentWorkspaceId = workspaceIdRef.current;
 89→      const prev = activeFileRef.current;
 90→      if (prev.workspaceId === currentWorkspaceId && prev.path === path) return;
 91→      activeFileRef.current = { workspaceId: currentWorkspaceId, path };
 92→      setActiveFile(path);
 93→      onActiveFileChangeRef.current?.(path);
 94→      workspaceLayoutActions.setSelectedFilePath(currentWorkspaceId, path);
 95→    }, []);
 96→
 97→    useEffect(() => {
 98→      const container = scrollContainerRef.current;
 99→      if (!container) return;
100→
101→      let rafId = 0;
102→
103→      const updateActiveFile = () => {
104→        rafId = 0;
105→        const changes = fileChangesRef.current;
106→        if (changes.length === 0) return;
107→
108→        const containerRect = container.getBoundingClientRect();
109→        // Threshold: a section is "active" if its top is within the top third
110→        // of the scroll container. This feels natural — the file you're reading
111→        // is the one near the top, not the one partially entering at the bottom.
112→        const threshold = containerRect.top + containerRect.height * 0.33;
113→
114→        let best: string | null = null;
115→
116→        for (const fc of changes) {
117→          const path = fc.file || fc.file_path || "";
118→          const el = sectionRefsMap.current.get(path);
119→          if (!el) continue;
120→
121→          const rect = el.getBoundingClientRect();
122→          // Section is visible if its bottom is below container top AND its top
123→          // is above the threshold line.
124→          if (rect.bottom > containerRect.top && rect.top <= threshold) {
125→            best = path;
126→          }
127→        }
128→
129→        // Fallback: if nothing passes the threshold (scrolled to very bottom),
130→        // pick the last section that's at least partially visible.
131→        if (best === null) {
132→          for (let i = changes.length - 1; i >= 0; i--) {
133→            const path = changes[i].file || changes[i].file_path || "";
134→            const el = sectionRefsMap.current.get(path);
135→            if (!el) continue;
136→            const rect = el.getBoundingClientRect();
137→            if (rect.top < containerRect.bottom && rect.bottom > containerRect.top) {
138→              best = path;
139→              break;
140→            }
141→          }
142→        }
143→
144→        setActiveFilePath(best);
145→      };
146→
147→      const onScroll = () => {
148→        if (rafId === 0) {
149→          rafId = requestAnimationFrame(updateActiveFile);
150→        }
151→      };
152→
153→      container.addEventListener("scroll", onScroll, { passive: true });
154→
155→      // Fire once on mount to set the initial active file
156→      requestAnimationFrame(updateActiveFile);
157→
158→      return () => {
159→        container.removeEventListener("scroll", onScroll);
160→        if (rafId !== 0) cancelAnimationFrame(rafId);
161→      };
162→    }, []); // Stable — reads fileChanges via ref; section registration uses callback refs
163→
164→    // One-shot scroll to initial target after sections mount and register refs
165→    useEffect(() => {
166→      if (!initialScrollTarget) return;
167→      const raf = requestAnimationFrame(() => {
168→        const target = resolveSection(initialScrollTarget);
169→        if (!target) return;
170→        setActiveFilePath(initialScrollTarget);
171→        target.scrollIntoView({
172→          behavior: "auto",
173→          block: "start",
174→        });
175→      });
176→      return () => cancelAnimationFrame(raf);
177→    }, [initialScrollTarget, workspaceId, resolveSection, setActiveFilePath]);
178→
179→    // Expose scrollToFile to parent — immediately updates active file
180→    // so the tree highlight changes without waiting for the scroll event.
181→    useImperativeHandle(
182→      ref,
183→      () => ({
184→        scrollToFile(path: string) {
185→          setActiveFilePath(path);
186→          const el = resolveSection(path);
187→          if (el) {
188→            el.scrollIntoView({ behavior: "smooth", block: "start" });
189→          }
190→        },
191→      }),
192→      [workspaceId, resolveSection]
193→    );
194→
195→    // Section ref callback — populates the ref map
196→    const sectionRefCallback = useCallback((filePath: string, el: HTMLDivElement | null) => {
197→      if (el) {
198→        sectionRefsMap.current.set(filePath, el);
199→      } else {
200→        sectionRefsMap.current.delete(filePath);
201→      }
202→    }, []);
203→
204→    const handleCollapseExpandAll = useCallback(() => {
205→      setExpandStateKey((prev) => prev + 1);
206→    }, []);
207→
208→    return (
209→      <div className={cn("flex h-full flex-col overflow-hidden", className)}>
210→        {/* Header bar — hidden when embedded in ChangesView */}
211→        {!hideHeader && (
212→          <div className="bg-muted/20 border-border/40 flex h-8 flex-shrink-0 items-center justify-between border-b px-3">
