/**
 * FileChangeMinimap — Collapsed file tree that shows one colored line per changed file.
 *
 * Default state: thin vertical strip (~24px) on the right edge of the diff viewer.
 * On hover: a floating panel slides in showing the full DiffFilesTree.
 *
 * Each line's color encodes change type: green=added, yellow=modified, red=deleted.
 * Clicking a line scrolls the diff viewer to that file.
 *
 * The hover panel is rendered via Portal to escape ancestor overflow-hidden containers.
 * Hover-intent pattern: shared timeout between strip and panel prevents flicker.
 */

import { useState, useRef, useCallback, useMemo, useEffect } from "react";
import { createPortal } from "react-dom";
import { AnimatePresence, m } from "framer-motion";
import { cn } from "@/shared/lib/utils";
import { DiffFilesTree } from "./DiffFilesTree";
import type { FileChange } from "@/shared/types";

interface FileChangeMinimapProps {
  fileChanges: FileChange[];
  selectedFile: string | null;
  onFileClick: (path: string) => void;
}

// --- Helpers ---

function filePath(fc: FileChange): string {
  return fc.file || fc.file_path || "";
}

type ChangeStatus = "added" | "modified" | "deleted";

function getChangeStatus(fc: FileChange): ChangeStatus {
  if (fc.additions > 0 && fc.deletions === 0) return "added";
  if (fc.deletions > 0 && fc.additions === 0) return "deleted";
  return "modified";
}

const STATUS_BG: Record<ChangeStatus, string> = {
  added: "bg-success",
  modified: "bg-warning",
  deleted: "bg-destructive",
};

// --- Animation config ---

const HOVER_ENTER_DELAY = 150; // ms before panel appears
const HOVER_LEAVE_DELAY = 200; // ms before panel disappears

const panelVariants = {
  hidden: { opacity: 0, x: 4 },
  visible: { opacity: 1, x: 0 },
};

const panelTransition = {
  duration: 0.15,
  ease: [0.165, 0.84, 0.44, 1], // ease-out-quart
};

// --- Component ---

export function FileChangeMinimap({ fileChanges, selectedFile, onFileClick }: FileChangeMinimapProps) {
  const [showPanel, setShowPanel] = useState(false);
  const showPanelRef = useRef(false);
  const leaveTimeoutRef = useRef<ReturnType<typeof setTimeout>>();
  const enterTimeoutRef = useRef<ReturnType<typeof setTimeout>>();
  const stripRef = useRef<HTMLDivElement>(null);

  // Position for the portal-rendered panel (fixed relative to viewport)
  const [panelRect, setPanelRect] = useState({ top: 0, right: 0, height: 0 });

  // Keep ref in sync with state — avoids stale closures in stable callbacks
  useEffect(() => {
    showPanelRef.current = showPanel;
  });

  // Cleanup timeouts on unmount
  useEffect(() => {
    return () => {
      clearTimeout(leaveTimeoutRef.current);
      clearTimeout(enterTimeoutRef.current);
    };
  }, []);

  // Recalculate panel position when it opens — anchored to the strip's left edge
  useEffect(() => {
    if (!showPanel || !stripRef.current) return;
    const rect = stripRef.current.getBoundingClientRect();
    setPanelRect({
      top: rect.top,
      right: window.innerWidth - rect.left,
      height: rect.height,
    });
  }, [showPanel]);

  // Shared hover-intent: entering either strip or panel keeps the panel open.
  // Uses ref to read showPanel without re-creating the callback on every toggle.
  const handleMouseEnter = useCallback(() => {
    clearTimeout(leaveTimeoutRef.current);
    if (!showPanelRef.current) {
      enterTimeoutRef.current = setTimeout(() => setShowPanel(true), HOVER_ENTER_DELAY);
    }
  }, []);

  const handleMouseLeave = useCallback(() => {
    clearTimeout(enterTimeoutRef.current);
    leaveTimeoutRef.current = setTimeout(() => setShowPanel(false), HOVER_LEAVE_DELAY);
  }, []);

  // Memoize the line data to avoid re-computing on every render
  const lines = useMemo(
    () => fileChanges.map((fc) => ({ path: filePath(fc), status: getChangeStatus(fc) })),
    [fileChanges]
  );

  return (
    <div className="flex h-full flex-shrink-0">
      {/* Strip — thin column of colored lines */}
      <div
        ref={stripRef}
        className="border-border/30 flex w-6 flex-col items-center gap-[3px] border-l py-3"
        onMouseEnter={handleMouseEnter}
        onMouseLeave={handleMouseLeave}
      >
        {lines.map((line) => (
          <button
            key={line.path}
            type="button"
            onClick={() => onFileClick(line.path)}
            className={cn(
              "h-[2px] flex-shrink-0 rounded-full transition-all duration-150",
              STATUS_BG[line.status],
              selectedFile === line.path ? "w-3.5 opacity-100" : "w-2.5 opacity-60"
            )}
            aria-label={`${line.path} (${line.status})`}
          />
        ))}
      </div>

      {/* Floating panel — rendered in a Portal to escape overflow-hidden ancestors */}
      {createPortal(
        <AnimatePresence>
          {showPanel && (
            <m.div
              initial="hidden"
              animate="visible"
              exit="hidden"
              variants={panelVariants}
              transition={panelTransition}
              style={{
                position: "fixed",
                top: panelRect.top,
                right: panelRect.right,
                height: panelRect.height,
              }}
              className="border-border/40 bg-background z-50 w-60 rounded-l-lg border shadow-lg"
              onMouseEnter={handleMouseEnter}
              onMouseLeave={handleMouseLeave}
            >
              {/* Header */}
              <div className="border-border/30 flex h-8 items-center justify-between border-b px-3">
                <span className="text-text-muted text-xs">Files</span>
                <span className="text-text-muted/60 text-[10px] tabular-nums">
                  {fileChanges.length}
                </span>
              </div>

              {/* File tree — reused as-is */}
              <div className="h-[calc(100%-2rem)] overflow-hidden">
                <DiffFilesTree
                  fileChanges={fileChanges}
                  selectedFile={selectedFile}
                  onFileClick={onFileClick}
                />
              </div>
            </m.div>
          )}
        </AnimatePresence>,
        document.body
      )}
    </div>
  );
}

