/**
 * Changes View — Self-contained diff viewer for the Changes content tab.
 *
 * Two layout modes (persisted per workspace):
 * - Minimap (default): full-width diff viewer + thin colored strip on right edge.
 *   Hovering the strip reveals a floating file tree panel.
 * - Pinned: resizable two-panel layout with permanent file tree sidebar.
 *
 * Also supports a compact mode (mobile) that shows only the diff viewer.
 */

import { useRef, useMemo, useCallback, useState } from "react";
import {
  GitBranch,
  SlidersHorizontal,
  ChevronDown,
  Check,
  ScanText,
  PanelRightClose,
} from "lucide-react";
import {
  DropdownMenu,
  DropdownMenuTrigger,
  DropdownMenuContent,
  DropdownMenuItem,
} from "@/components/ui/dropdown-menu";
import { ResizablePanelGroup, ResizablePanel, ResizableHandle } from "@/components/ui/resizable";
import { cn } from "@/shared/lib/utils";
import { useWorkspaceLayout } from "../hooks/useWorkspaceLayout";
import { useFileChanges } from "../api/workspace.queries";
import { AllFilesDiffViewer, type AllFilesDiffViewerRef } from "./AllFilesDiffViewer";
import { DiffFilesTree } from "./DiffFilesTree";
import { FileChangeMinimap } from "./FileChangeMinimap";
import {
  CHANGES_FILTER_OPTIONS,
  changesFilterLabel,
  type ChangesFilter,
} from "../lib/changesFilter";
import type { Workspace } from "@/shared/types";

interface ChangesViewProps {
  workspace: Workspace;
  /** Whether file watcher is active — disables polling in useFileChanges */
  isWatched?: boolean;
  /** Callback to insert a code review prompt into the chat input */
  onReview?: () => void;
  /** Single-column layout without file tree side panel (used on mobile) */
  compact?: boolean;
}

export function ChangesView({ workspace, isWatched = false, onReview, compact }: ChangesViewProps) {
  const { selectedFilePath, fileTreePinned, setFileTreePinned } = useWorkspaceLayout(workspace.id);
  const diffViewerRef = useRef<AllFilesDiffViewerRef>(null);
  const [changesFilter, setChangesFilter] = useState<ChangesFilter>("all-changes");

  const isReady = workspace.state === "ready";

  // Fetch file change data
  const { data: fileChangesData } = useFileChanges(
    isReady ? workspace.id : null,
    workspace.session_status,
    isWatched,
    workspace.state
  );
  const fileChanges = useMemo(() => fileChangesData?.files ?? [], [fileChangesData]);

  // TODO: Wire up uncommitted/last-turn filters when backend endpoints exist.
  // For now, changesFilter is always "all-changes" (other options are commented out
  // in CHANGES_FILTER_OPTIONS). When adding new filters, fetch the extra data here
  // and use a match() to select the active list.
  const filteredFileChanges = fileChanges;

  // Scroll the diff viewer to the clicked file
  const handleFileClick = useCallback((path: string) => {
    diffViewerRef.current?.scrollToFile(path);
  }, []);

  const handlePin = useCallback(() => setFileTreePinned(true), [setFileTreePinned]);
  const handleUnpin = useCallback(() => setFileTreePinned(false), [setFileTreePinned]);

  const activeFilterLabel = changesFilterLabel(changesFilter);

  return (
    <div className="flex h-full flex-col overflow-hidden">
      {/* Header — filter dropdown (left) + review button (right) */}
      <div className="border-border-subtle flex h-10 flex-shrink-0 items-center justify-between border-b px-4">
        <DropdownMenu>
          <DropdownMenuTrigger asChild>
            <button
              type="button"
              className="text-text-muted hover:text-text-secondary ease flex items-center gap-1 rounded-lg px-1.5 py-1 text-sm transition-colors duration-200"
            >
              <SlidersHorizontal className="h-[11px] w-[11px]" />
              <span>{activeFilterLabel}</span>
              <ChevronDown className="h-[10px] w-[10px]" />
            </button>
          </DropdownMenuTrigger>
          <DropdownMenuContent align="start" className="min-w-[140px]">
            {CHANGES_FILTER_OPTIONS.map(([value, label]) => (
              <DropdownMenuItem
                key={value}
                onClick={() => setChangesFilter(value)}
                className="gap-2 text-xs"
              >
                <Check
                  className={cn("h-3 w-3", changesFilter === value ? "opacity-100" : "opacity-0")}
                />
                {label}
              </DropdownMenuItem>
            ))}
          </DropdownMenuContent>
        </DropdownMenu>

        {onReview && filteredFileChanges.length > 0 && (
          <button
            type="button"
            onClick={onReview}
            className="bg-primary/8 hover:bg-primary/14 text-primary ease flex h-7 items-center gap-1.5 rounded-lg px-2.5 text-xs font-medium transition-colors duration-200"
          >
            <ScanText className="h-3 w-3" />
            <span>Review Changes</span>
            <span className="text-primary/60 ml-0.5 text-[10px] font-normal">
              {filteredFileChanges.length}
            </span>
          </button>
        )}
      </div>

      {/* Content area */}
      {filteredFileChanges.length === 0 ? (
        <div className="flex flex-1 flex-col items-center justify-center gap-3">
          <div className="bg-bg-muted/30 flex h-10 w-10 items-center justify-center rounded-xl">
            <GitBranch className="text-text-muted/50 h-5 w-5" aria-hidden="true" />
          </div>
          <p className="text-text-muted/60 text-xs">No file changes yet</p>
          <p className="text-text-muted/40 max-w-[200px] text-center text-[11px]">
            Changes will appear here as the agent modifies files
          </p>
        </div>
      ) : compact ? (
        <AllFilesDiffViewer
          ref={diffViewerRef}
          workspaceId={workspace.id}
          fileChanges={filteredFileChanges}
          hideHeader
        />
      ) : fileTreePinned ? (
        /* Pinned mode — resizable two-panel layout with permanent file tree */
        <ResizablePanelGroup direction="horizontal" className="min-h-0 flex-1">
          <ResizablePanel defaultSize={75} minSize={30}>
            <AllFilesDiffViewer
              ref={diffViewerRef}
              workspaceId={workspace.id}
              fileChanges={filteredFileChanges}
              hideHeader
            />
          </ResizablePanel>

          <ResizableHandle />

          <ResizablePanel
            defaultSize={25}
            minSize={15}
            collapsible
            collapsedSize={0}
            onCollapse={handleUnpin}
          >
            <div className="flex h-full flex-col overflow-hidden">
              {/* Pinned panel header with collapse button */}
              <div className="border-border/30 flex h-8 flex-shrink-0 items-center justify-between border-b px-3">
                <span className="text-text-muted text-xs">Files</span>
                <div className="flex items-center gap-1.5">
                  <span className="text-text-muted/60 text-[10px] tabular-nums">
                    {filteredFileChanges.length}
                  </span>
                  <button
                    type="button"
                    onClick={handleUnpin}
                    className="text-text-muted hover:text-text-secondary hover:bg-muted/50 ease flex h-5 w-5 items-center justify-center rounded-md transition-colors duration-150"
                    title="Collapse to minimap"
                  >
                    <PanelRightClose className="h-3 w-3" />
                  </button>
                </div>
              </div>
              <DiffFilesTree
                fileChanges={filteredFileChanges}
                selectedFile={selectedFilePath ?? null}
                onFileClick={handleFileClick}
              />
            </div>
          </ResizablePanel>
        </ResizablePanelGroup>
      ) : (
        /* Minimap mode — full-width diff viewer + thin strip on right */
        <div className="flex min-h-0 flex-1">
          <AllFilesDiffViewer
            ref={diffViewerRef}
            workspaceId={workspace.id}
            fileChanges={filteredFileChanges}
            hideHeader
            className="min-w-0 flex-1"
          />
          <FileChangeMinimap
            fileChanges={filteredFileChanges}
            selectedFile={selectedFilePath ?? null}
            onFileClick={handleFileClick}
            onPin={handlePin}
          />
        </div>
      )}
    </div>
  );
}

/**
 * FileChangeMinimap — Collapsed file tree that shows one colored line per changed file.
 *
 * Default state: thin vertical strip (~24px) on the right edge of the diff viewer.
 * On hover: a floating panel slides in showing the full DiffFilesTree.
 *
 * Each line's color encodes change type: green=added, yellow=modified, red=deleted.
 * Clicking a line scrolls the diff viewer to that file.
 *
 * The hover panel is rendered via Portal to escape ancestor overflow-hidden containers.
 * Hover-intent pattern: shared timeout between strip and panel prevents flicker.
 */

import { useState, useRef, useCallback, useMemo, useEffect } from "react";
import { createPortal } from "react-dom";
import { AnimatePresence, m } from "framer-motion";
import { PinIcon } from "lucide-react";
import { cn } from "@/shared/lib/utils";
import { DiffFilesTree } from "./DiffFilesTree";
import type { FileChange } from "@/shared/types";

interface FileChangeMinimapProps {
  fileChanges: FileChange[];
  selectedFile: string | null;
  onFileClick: (path: string) => void;
  /** Called when the user pins the hover panel open (switches to expanded mode) */
  onPin: () => void;
}

// --- Helpers ---

function filePath(fc: FileChange): string {
  return fc.file || fc.file_path || "";
}

type ChangeStatus = "added" | "modified" | "deleted";

function getChangeStatus(fc: FileChange): ChangeStatus {
  if (fc.additions > 0 && fc.deletions === 0) return "added";
  if (fc.deletions > 0 && fc.additions === 0) return "deleted";
  return "modified";
}

const STATUS_BG: Record<ChangeStatus, string> = {
  added: "bg-success",
  modified: "bg-warning",
  deleted: "bg-destructive",
};

// --- Animation config ---

const HOVER_ENTER_DELAY = 150; // ms before panel appears
const HOVER_LEAVE_DELAY = 200; // ms before panel disappears

const panelVariants = {
  hidden: { opacity: 0, x: 4 },
  visible: { opacity: 1, x: 0 },
};

const panelTransition = {
  duration: 0.15,
  ease: [0.165, 0.84, 0.44, 1], // ease-out-quart
};

// --- Component ---

export function FileChangeMinimap({ fileChanges, selectedFile, onFileClick, onPin }: FileChangeMinimapProps) {
  const [showPanel, setShowPanel] = useState(false);
  const showPanelRef = useRef(false);
  const leaveTimeoutRef = useRef<ReturnType<typeof setTimeout>>();
  const enterTimeoutRef = useRef<ReturnType<typeof setTimeout>>();
  const stripRef = useRef<HTMLDivElement>(null);

  // Position for the portal-rendered panel (fixed relative to viewport)
  const [panelRect, setPanelRect] = useState({ top: 0, right: 0, height: 0 });

  // Keep ref in sync with state — avoids stale closures in stable callbacks
  useEffect(() => {
    showPanelRef.current = showPanel;
  });

  // Cleanup timeouts on unmount
  useEffect(() => {
    return () => {
      clearTimeout(leaveTimeoutRef.current);
      clearTimeout(enterTimeoutRef.current);
    };
  }, []);

  // Recalculate panel position when it opens — anchored to the strip's left edge
  useEffect(() => {
    if (!showPanel || !stripRef.current) return;
    const rect = stripRef.current.getBoundingClientRect();
    setPanelRect({
      top: rect.top,
      right: window.innerWidth - rect.left,
      height: rect.height,
    });
  }, [showPanel]);

  // Shared hover-intent: entering either strip or panel keeps the panel open.
  // Uses ref to read showPanel without re-creating the callback on every toggle.
  const handleMouseEnter = useCallback(() => {
    clearTimeout(leaveTimeoutRef.current);
    if (!showPanelRef.current) {
      enterTimeoutRef.current = setTimeout(() => setShowPanel(true), HOVER_ENTER_DELAY);
    }
  }, []);

  const handleMouseLeave = useCallback(() => {
    clearTimeout(enterTimeoutRef.current);
    leaveTimeoutRef.current = setTimeout(() => setShowPanel(false), HOVER_LEAVE_DELAY);
  }, []);

  // Memoize the line data to avoid re-computing on every render
  const lines = useMemo(
    () => fileChanges.map((fc) => ({ path: filePath(fc), status: getChangeStatus(fc) })),
    [fileChanges]
  );

  return (
    <div className="flex h-full flex-shrink-0">
      {/* Strip — thin column of colored lines */}
      <div
        ref={stripRef}
        className="border-border/30 flex w-6 flex-col items-center gap-[3px] border-l py-3"
        onMouseEnter={handleMouseEnter}
        onMouseLeave={handleMouseLeave}
      >
        {lines.map((line) => (
          <button
            key={line.path}
            type="button"
            onClick={() => onFileClick(line.path)}
            className={cn(
              "h-[2px] flex-shrink-0 rounded-full transition-all duration-150",
              STATUS_BG[line.status],
              selectedFile === line.path ? "w-3.5 opacity-100" : "w-2.5 opacity-60"
            )}
            aria-label={`${line.path} (${line.status})`}
          />
        ))}
      </div>

      {/* Floating panel — rendered in a Portal to escape overflow-hidden ancestors */}
      {createPortal(
        <AnimatePresence>
          {showPanel && (
            <m.div
              initial="hidden"
              animate="visible"
              exit="hidden"
              variants={panelVariants}
              transition={panelTransition}
              style={{
                position: "fixed",
                top: panelRect.top,
                right: panelRect.right,
                height: panelRect.height,
              }}
              className="border-border/40 bg-background z-50 w-60 rounded-l-lg border shadow-lg"
              onMouseEnter={handleMouseEnter}
              onMouseLeave={handleMouseLeave}
            >
              {/* Header */}
              <div className="border-border/30 flex h-8 items-center justify-between border-b px-3">
                <span className="text-text-muted text-xs">Files</span>
                <div className="flex items-center gap-1.5">
                  <span className="text-text-muted/60 text-[10px] tabular-nums">
                    {fileChanges.length}
                  </span>
                  <button
                    type="button"
                    onClick={onPin}
                    className="text-text-muted hover:text-text-secondary hover:bg-muted/50 ease flex h-5 w-5 items-center justify-center rounded-md transition-colors duration-150"
                    title="Pin file tree open"
                  >
                    <PinIcon className="h-3 w-3" />
                  </button>
                </div>
              </div>

              {/* File tree — reused as-is */}
              <div className="h-[calc(100%-2rem)] overflow-hidden">
                <DiffFilesTree
                  fileChanges={fileChanges}
                  selectedFile={selectedFile}
                  onFileClick={onFileClick}
                />
              </div>
            </m.div>
          )}
        </AnimatePresence>,
        document.body
      )}
    </div>
  );
}

