  change_status?: "added" | "modified" | "deleted";
  /** true = committed (in HEAD), false = uncommitted (working dir only) */
  committed?: boolean;
}

export interface FileTreeResponse {
  files: FileTreeNode[];
  totalFiles: number;
  totalSize: number;
}

