  onViewSetupLogs,
  setCreatePRHandler,
  setSendAgentMessageHandler,
  isWatched,
  manifestTasks,
  hasManifest,
  onRunTask,
  onStatusChange,
  prStatus,
  ghStatus,
  onCreatePR,
  onArchive,
  targetBranch,
  onTargetBranchChange,
}: MobileLayoutProps) {
