/**
 * Workspace Layout Hook
 * Provides workspace-specific layout state with proper store synchronization.
 *
 * Reads directly from the store and provides stable callbacks that update it.
 *
 * Usage:
 * ```typescript
 * const {
 *   contentTab,
 *   selectedFilePath,
 *   setContentTab,
 *   setSelectedFilePath,
 * } = useWorkspaceLayout(workspaceId);
 * ```
 */

import { useCallback } from "react";
import { useShallow } from "zustand/react/shallow";
import {
  useWorkspaceLayoutStore,
  workspaceLayoutActions,
  defaultLayout,
} from "../store/workspaceLayoutStore";
import type { ContentTab } from "../store/workspaceLayoutStore";

interface UseWorkspaceLayoutResult {
  /** Current content panel tab (changes, files, terminal, browser, config, etc.) */
  contentTab: ContentTab;
  /** Currently selected file path (for highlighting in tree) */
  selectedFilePath: string | null;
  /** Whether sidebar is collapsed */
  sidebarCollapsed: boolean;
  /** Whether chat panel is collapsed */
  chatPanelCollapsed: boolean;
  /** Whether content panel is collapsed */
  contentPanelCollapsed: boolean;
  /** Whether file tree is pinned open (vs minimap mode) */
  fileTreePinned: boolean;

  /** Set the active content tab */
  setContentTab: (tab: ContentTab) => void;
  /** Set selected file path */
  setSelectedFilePath: (path: string | null) => void;
  /** Set sidebar collapsed state */
  setSidebarCollapsed: (collapsed: boolean) => void;
  /** Set chat panel collapsed state */
  setChatPanelCollapsed: (collapsed: boolean) => void;
  /** Set content panel collapsed state */
  setContentPanelCollapsed: (collapsed: boolean) => void;
  /** Set file tree pinned state */
  setFileTreePinned: (pinned: boolean) => void;
  /** Update multiple layout properties at once */
  updateLayout: (updates: {
    contentTab?: ContentTab;
    selectedFilePath?: string | null;
    sidebarCollapsed?: boolean;
  }) => void;
}

export function useWorkspaceLayout(workspaceId: string | null): UseWorkspaceLayoutResult {
  const layout = useWorkspaceLayoutStore(
    useShallow((state) =>
      workspaceId ? (state.layouts[workspaceId] ?? defaultLayout) : defaultLayout
    )
  );
  const { setLayout } = workspaceLayoutActions;

  const setContentTab = useCallback(
    (tab: ContentTab) => {
      if (workspaceId) {
        setLayout(workspaceId, { activeContentTab: tab });
      }
    },
    [workspaceId, setLayout]
  );

  const setSelectedFilePath = useCallback(
    (path: string | null) => {
      if (workspaceId) {
        setLayout(workspaceId, { selectedFilePath: path });
      }
    },
    [workspaceId, setLayout]
  );

  const setSidebarCollapsed = useCallback(
    (collapsed: boolean) => {
      if (workspaceId) {
        setLayout(workspaceId, { sidebarCollapsed: collapsed });
      }
    },
    [workspaceId, setLayout]
  );

  const setChatPanelCollapsed = useCallback(
    (collapsed: boolean) => {
      if (workspaceId) {
        setLayout(workspaceId, { chatPanelCollapsed: collapsed });
      }
    },
    [workspaceId, setLayout]
  );

  const setContentPanelCollapsed = useCallback(
    (collapsed: boolean) => {
      if (workspaceId) {
        setLayout(workspaceId, { contentPanelCollapsed: collapsed });
      }
    },
    [workspaceId, setLayout]
  );

  const setFileTreePinned = useCallback(
    (pinned: boolean) => {
      if (workspaceId) {
        setLayout(workspaceId, { fileTreePinned: pinned });
      }
    },
    [workspaceId, setLayout]
  );

  const updateLayout = useCallback(
    (updates: {
      contentTab?: ContentTab;
      selectedFilePath?: string | null;
      sidebarCollapsed?: boolean;
    }) => {
      if (!workspaceId) return;

      const layoutUpdates: Parameters<typeof setLayout>[1] = {};

      if (updates.contentTab !== undefined) {
        layoutUpdates.activeContentTab = updates.contentTab;
      }
      if (updates.selectedFilePath !== undefined) {
        layoutUpdates.selectedFilePath = updates.selectedFilePath;
      }
      if (updates.sidebarCollapsed !== undefined) {
        layoutUpdates.sidebarCollapsed = updates.sidebarCollapsed;
      }

      setLayout(workspaceId, layoutUpdates);
    },
    [workspaceId, setLayout]
  );

  return {
    contentTab: layout.activeContentTab ?? defaultLayout.activeContentTab,
    selectedFilePath: layout.selectedFilePath ?? null,
    sidebarCollapsed: layout.sidebarCollapsed,
    chatPanelCollapsed: layout.chatPanelCollapsed ?? false,
    contentPanelCollapsed: layout.contentPanelCollapsed ?? false,
    fileTreePinned: layout.fileTreePinned ?? false,

    setContentTab,
    setSelectedFilePath,
    setSidebarCollapsed,
    setChatPanelCollapsed,
    setContentPanelCollapsed,
    setFileTreePinned,
    updateLayout,
  };
}

/**
 * ChangesMinimap — Collapsed file tree that shows one colored line per changed file.
 *
 * Default state: thin vertical strip (~24px) on the right edge of the diff viewer.
 * On hover: a floating panel slides in showing the full ChangesFilesPanel.
 *
 * Each line's color encodes change type: green=added, yellow=modified, red=deleted.
 * Clicking a line scrolls the diff viewer to that file.
 *
 * The hover panel is rendered via Portal to escape ancestor overflow-hidden containers.
 * Hover-intent pattern: shared timeout between strip and panel prevents flicker.
 */

import { useState, useRef, useCallback, useMemo, useEffect } from "react";
import { createPortal } from "react-dom";
import { AnimatePresence, m } from "framer-motion";
import { PinIcon } from "lucide-react";
import { cn } from "@/shared/lib/utils";
import { getChangeStatus, STATUS_BG, fileChangePath } from "../lib/workspace.utils";
import { ChangesFilesPanel } from "./ChangesFilesPanel";
import type { FileChange } from "@/shared/types";

interface ChangesMinimapProps {
  fileChanges: FileChange[];
  selectedFile: string | null;
  onFileClick: (path: string) => void;
  /** Called when the user pins the hover panel open (switches to expanded mode) */
  onPin: () => void;
}

// --- Animation config ---

const HOVER_ENTER_DELAY = 150; // ms before panel appears
const HOVER_LEAVE_DELAY = 200; // ms before panel disappears

const panelVariants = {
  hidden: { opacity: 0, x: 4 },
  visible: { opacity: 1, x: 0 },
};

const panelTransition = {
  duration: 0.15,
  ease: [0.165, 0.84, 0.44, 1], // ease-out-quart
};

// --- Component ---

export function ChangesMinimap({ fileChanges, selectedFile, onFileClick, onPin }: ChangesMinimapProps) {
  const [showPanel, setShowPanel] = useState(false);
  const showPanelRef = useRef(false);
  const leaveTimeoutRef = useRef<ReturnType<typeof setTimeout>>();
  const enterTimeoutRef = useRef<ReturnType<typeof setTimeout>>();
  const stripRef = useRef<HTMLDivElement>(null);

  // Position for the portal-rendered panel (fixed relative to viewport)
  const [panelRect, setPanelRect] = useState({ top: 0, right: 0, height: 0 });

  // Keep ref in sync with state — avoids stale closures in stable callbacks
  useEffect(() => {
    showPanelRef.current = showPanel;
  });

  // Cleanup timeouts on unmount
  useEffect(() => {
    return () => {
      clearTimeout(leaveTimeoutRef.current);
      clearTimeout(enterTimeoutRef.current);
    };
  }, []);

  // Recalculate panel position when it opens — anchored to the strip's left edge
  useEffect(() => {
    if (!showPanel || !stripRef.current) return;
    const rect = stripRef.current.getBoundingClientRect();
    setPanelRect({
      top: rect.top,
      right: window.innerWidth - rect.left,
      height: rect.height,
    });
  }, [showPanel]);

  // Shared hover-intent: entering either strip or panel keeps the panel open.
  // Uses ref to read showPanel without re-creating the callback on every toggle.
  const handleMouseEnter = useCallback(() => {
    clearTimeout(leaveTimeoutRef.current);
    if (!showPanelRef.current) {
      enterTimeoutRef.current = setTimeout(() => setShowPanel(true), HOVER_ENTER_DELAY);
    }
  }, []);

  const handleMouseLeave = useCallback(() => {
    clearTimeout(enterTimeoutRef.current);
    leaveTimeoutRef.current = setTimeout(() => setShowPanel(false), HOVER_LEAVE_DELAY);
  }, []);

  // Clicking a file in either the strip or the hover panel pins the tree open
  const handleFileClickAndPin = useCallback(
    (path: string) => {
      onFileClick(path);
      onPin();
    },
    [onFileClick, onPin]
  );

  // Memoize the line data to avoid re-computing on every render
  const lines = useMemo(
    () => fileChanges.map((fc) => ({ path: fileChangePath(fc), status: getChangeStatus(fc) })),
    [fileChanges]
  );

  return (
    <div className="flex h-full flex-shrink-0">
      {/* Strip — thin column of colored lines */}
      <div
        ref={stripRef}
        className="border-border/30 flex w-6 flex-col items-center gap-[3px] border-l py-3"
        onMouseEnter={handleMouseEnter}
        onMouseLeave={handleMouseLeave}
      >
        {lines.map((line) => (
          <button
            key={line.path}
            type="button"
            onClick={() => handleFileClickAndPin(line.path)}
            className={cn(
              "h-[2px] flex-shrink-0 rounded-full transition-all duration-150",
              STATUS_BG[line.status],
              selectedFile === line.path ? "w-3.5 opacity-100" : "w-2.5 opacity-60"
            )}
            aria-label={`${line.path} (${line.status})`}
          />
        ))}
      </div>

      {/* Floating panel — rendered in a Portal to escape overflow-hidden ancestors */}
      {createPortal(
        <AnimatePresence>
          {showPanel && (
            <m.div
              initial="hidden"
              animate="visible"
              exit="hidden"
              variants={panelVariants}
              transition={panelTransition}
              style={{
                position: "fixed",
                top: panelRect.top,
                right: panelRect.right,
                height: panelRect.height,
              }}
              className="border-border/40 bg-background z-50 w-60 rounded-l-lg border shadow-lg"
              onMouseEnter={handleMouseEnter}
              onMouseLeave={handleMouseLeave}
            >
              {/* Header */}
              <div className="border-border/30 flex h-8 items-center justify-between border-b px-3">
                <div className="flex items-center gap-1.5">
                  <span className="text-text-muted text-xs">Files</span>
                  <span className="text-text-muted/60 text-[10px] tabular-nums">
                    {fileChanges.length}
                  </span>
                </div>
                <button
                  type="button"
                  onClick={onPin}
                  className="text-text-muted hover:text-text-secondary hover:bg-muted/50 ease flex h-5 w-5 items-center justify-center rounded-md transition-colors duration-150"
                  title="Pin file tree open"
                >
                  <PinIcon className="h-3 w-3" />
                </button>
              </div>

              {/* File tree — reused as-is */}
              <div className="h-[calc(100%-2rem)] overflow-hidden">
                <ChangesFilesPanel
                  fileChanges={fileChanges}
                  selectedFile={selectedFile}
                  onFileClick={handleFileClickAndPin}
                />
              </div>
            </m.div>
          )}
        </AnimatePresence>,
        document.body
      )}
    </div>
  );
}

