  3→// --- File change status helpers (shared by ChangesFilesPanel, ChangesMinimap, etc.) ---
  4→
  5→export type ChangeStatus = "added" | "modified" | "deleted";
  6→
  7→/** Derive change status from line additions/deletions */
  8→export function getChangeStatus(change: FileChange): ChangeStatus {
  9→  if (change.additions > 0 && change.deletions === 0) return "added";
 10→  if (change.deletions > 0 && change.additions === 0) return "deleted";
 11→  return "modified";
 12→}
 13→
 14→/** Tailwind bg class for each status — used for dots, minimap lines, etc. */
 15→export const STATUS_BG: Record<ChangeStatus, string> = {
 16→  added: "bg-success",
 17→  modified: "bg-warning",
 18→  deleted: "bg-destructive",
 19→};
 20→
 21→/** Resolve the file path from a FileChange (handles both `file` and `file_path` fields) */
 22→export function fileChangePath(fc: FileChange): string {
 23→  return fc.file || fc.file_path || "";
 24→}
