 27→
 28→/**
 29→ * Create an optimistic (placeholder) Workspace object for instant UI feedback
 30→ * while the backend creates the real workspace asynchronously.
 31→ *
 32→ * Used in:
 33→ * - useRepoActions.createAndSelectWorkspace() (quick "+" button flow)
 34→ * - useRepoActions.handleOpenProject() (native folder dialog flow)
 35→ * - useRepoActions.handleCloneRepository() (git clone flow)
 36→ * - useCreateWorkspace() onMutate (React Query optimistic update)
 37→ */
 38→export function createOptimisticWorkspace(repoId: string, repoName: string): Workspace {
 39→  return {
 40→    id: `optimistic-${Date.now()}`,
 41→    repository_id: repoId,
 42→    slug: "",
 43→    title: null,
 44→    git_branch: null,
 45→    git_target_branch: null,
 46→    state: "initializing",
 47→    status: "in-progress",
 48→    current_session_id: null,
 49→    session_status: null,
 50→    model: null,
 51→    session_error_category: null,
 52→    session_error_message: null,
 53→    latest_message_sent_at: null,
 54→    init_stage: null,
 55→    setup_status: "none",
 56→    error_message: null,
 57→    updated_at: new Date().toISOString(),
 58→    repo_name: repoName,
 59→    root_path: "",
 60→    workspace_path: "",
 61→  };
 62→}
 63→
 64→/**
 65→ * Merge a workspace delta (q:delta) into the existing RepoGroup[] cache.
 66→ * Replaces matching workspaces by ID within their repo group, or appends if new.
 67→ * Used by useQuerySubscription's mergeDelta option.
 68→ */
 69→export function mergeWorkspaceDelta(
 70→  old: unknown,
 71→  upserted?: unknown[],
 72→  removed?: string[]
 73→): unknown {
 74→  if (!Array.isArray(old)) return old;
 75→  const groups = old as RepoGroup[];
 76→  if (!upserted && !removed) return old;
 77→
 78→  let result = groups.map((g) => ({ ...g, workspaces: [...g.workspaces] }));
 79→
 80→  if (removed?.length) {
 81→    const removeSet = new Set(removed);
 82→    result = result.map((g) => ({
 83→      ...g,
 84→      workspaces: g.workspaces.filter((w) => !removeSet.has(w.id)),
 85→    }));
 86→  }
 87→
 88→  if (upserted?.length) {
 89→    for (const item of upserted) {
 90→      const ws = item as Workspace;
 91→      const group = result.find((g) => g.repo_id === ws.repository_id);
 92→      if (!group) continue;
 93→      const idx = group.workspaces.findIndex((w) => w.id === ws.id);
 94→      if (idx >= 0) {
 95→        group.workspaces[idx] = ws;
 96→      } else {
 97→        group.workspaces.push(ws);
 98→      }
 99→    }
100→  }
101→
102→  return result;
103→}
