  1→/**
  2→ * ChangesMinimap — Collapsed file tree that shows one colored line per changed file.
  3→ *
  4→ * Default state: thin vertical strip (~24px) on the right edge of the diff viewer.
  5→ * On hover: a floating panel slides in showing the full ChangesFilesPanel.
  6→ *
  7→ * Each line's color encodes change type: green=added, yellow=modified, red=deleted.
  8→ * Clicking a line scrolls the diff viewer to that file.
  9→ *
 10→ * The hover panel is rendered via Portal to escape ancestor overflow-hidden containers.
 11→ * Hover-intent pattern: shared timeout between strip and panel prevents flicker.
 12→ */
 13→
 14→import { useState, useRef, useCallback, useMemo, useEffect } from "react";
 15→import { createPortal } from "react-dom";
 16→import { AnimatePresence, m } from "framer-motion";
 17→import { PinIcon } from "lucide-react";
 18→import { cn } from "@/shared/lib/utils";
 19→import { getChangeStatus, STATUS_BG, fileChangePath } from "../lib/workspace.utils";
 20→import { ChangesFilesPanel } from "./ChangesFilesPanel";
 21→import type { FileChange } from "@/shared/types";
 22→
 23→interface ChangesMinimapProps {
 24→  fileChanges: FileChange[];
 25→  selectedFile: string | null;
 26→  onFileClick: (path: string) => void;
 27→  /** Called when the user pins the hover panel open (switches to expanded mode) */
 28→  onPin: () => void;
 29→}
 30→
 31→// --- Animation config ---
 32→
 33→const HOVER_ENTER_DELAY = 150; // ms before panel appears
 34→const HOVER_LEAVE_DELAY = 200; // ms before panel disappears
 35→
 36→const panelVariants = {
 37→  hidden: { opacity: 0, x: 4 },
 38→  visible: { opacity: 1, x: 0 },
 39→};
 40→
 41→const panelTransition = {
 42→  duration: 0.15,
 43→  ease: [0.165, 0.84, 0.44, 1], // ease-out-quart
 44→};
 45→
 46→// --- Component ---
 47→
 48→export function ChangesMinimap({ fileChanges, selectedFile, onFileClick, onPin }: ChangesMinimapProps) {
 49→  const [showPanel, setShowPanel] = useState(false);
 50→  const showPanelRef = useRef(false);
 51→  const leaveTimeoutRef = useRef<ReturnType<typeof setTimeout>>();
 52→  const enterTimeoutRef = useRef<ReturnType<typeof setTimeout>>();
 53→  const stripRef = useRef<HTMLDivElement>(null);
 54→
 55→  // Position for the portal-rendered panel (fixed relative to viewport)
 56→  const [panelRect, setPanelRect] = useState({ top: 0, right: 0, height: 0 });
 57→
 58→  // Keep ref in sync with state — avoids stale closures in stable callbacks
 59→  useEffect(() => {
 60→    showPanelRef.current = showPanel;
 61→  });
 62→
 63→  // Cleanup timeouts on unmount
 64→  useEffect(() => {
 65→    return () => {
 66→      clearTimeout(leaveTimeoutRef.current);
 67→      clearTimeout(enterTimeoutRef.current);
 68→    };
 69→  }, []);
 70→
 71→  // Recalculate panel position when it opens — anchored to the strip's left edge
 72→  useEffect(() => {
 73→    if (!showPanel || !stripRef.current) return;
 74→    const rect = stripRef.current.getBoundingClientRect();
 75→    setPanelRect({
 76→      top: rect.top,
 77→      right: window.innerWidth - rect.left,
 78→      height: rect.height,
 79→    });
 80→  }, [showPanel]);
 81→
 82→  // Shared hover-intent: entering either strip or panel keeps the panel open.
 83→  // Uses ref to read showPanel without re-creating the callback on every toggle.
 84→  const handleMouseEnter = useCallback(() => {
 85→    clearTimeout(leaveTimeoutRef.current);
 86→    if (!showPanelRef.current) {
 87→      enterTimeoutRef.current = setTimeout(() => setShowPanel(true), HOVER_ENTER_DELAY);
 88→    }
 89→  }, []);
 90→
 91→  const handleMouseLeave = useCallback(() => {
 92→    clearTimeout(enterTimeoutRef.current);
