154→            >
155→              {/* Header */}
156→              <div className="border-border/30 flex h-8 items-center justify-between border-b px-3">
157→                <div className="flex items-center gap-1.5">
158→                  <span className="text-text-muted text-xs">Files</span>
159→                  <span className="text-text-muted/60 text-[10px] tabular-nums">
160→                    {fileChanges.length}
161→                  </span>
162→                </div>
163→                <button
164→                  type="button"
165→                  onClick={onPin}
166→                  className="text-text-muted hover:text-text-secondary hover:bg-muted/50 ease flex h-5 w-5 items-center justify-center rounded-md transition-colors duration-150"
167→                  title="Pin file tree open"
168→                >
169→                  <PinIcon className="h-3 w-3" />
170→                </button>
171→              </div>
172→
173→              {/* File tree — reused as-is */}
174→              <div className="h-[calc(100%-2rem)] overflow-hidden">
175→                <ChangesFilesPanel
176→                  fileChanges={fileChanges}
177→                  selectedFile={selectedFile}
178→                  onFileClick={handleFileClickAndPin}
179→                />
180→              </div>
181→            </m.div>
182→          )}
183→        </AnimatePresence>,
184→        document.body
185→      )}
186→    </div>
