  8→ *
  9→ * Also supports a compact mode (mobile) that shows only the diff viewer.
 10→ */
 11→
 12→import { useRef, useMemo, useCallback, useState } from "react";
 13→import {
 14→  GitBranch,
 15→  SlidersHorizontal,
 16→  ChevronDown,
 17→  Check,
 18→  ScanText,
 19→  PanelRight,
 20→} from "lucide-react";
 21→import {
 22→  DropdownMenu,
 23→  DropdownMenuTrigger,
 24→  DropdownMenuContent,
 25→  DropdownMenuItem,
 26→} from "@/components/ui/dropdown-menu";
 27→import { ResizablePanelGroup, ResizablePanel, ResizableHandle } from "@/components/ui/resizable";
 28→import { cn } from "@/shared/lib/utils";
 29→import { useWorkspaceLayout } from "../hooks/useWorkspaceLayout";
 30→import { useFileChanges } from "../api/workspace.queries";
 31→import { ChangesDiffViewer, type ChangesDiffViewerRef } from "./ChangesDiffViewer";
 32→import { ChangesFilesPanel } from "./ChangesFilesPanel";
 33→import { ChangesMinimap } from "./ChangesMinimap";
 34→import {
 35→  CHANGES_FILTER_OPTIONS,
 36→  changesFilterLabel,
 37→  type ChangesFilter,
 38→} from "../lib/changesFilter";
 39→import type { Workspace } from "@/shared/types";
 40→
 41→interface ChangesViewProps {
 42→  workspace: Workspace;
 43→  /** Whether file watcher is active — disables polling in useFileChanges */
 44→  isWatched?: boolean;
 45→  /** Callback to insert a code review prompt into the chat input */
 46→  onReview?: () => void;
 47→  /** Single-column layout without file tree side panel (used on mobile) */
 48→  compact?: boolean;
 49→}
 50→
 51→export function ChangesView({ workspace, isWatched = false, onReview, compact }: ChangesViewProps) {
 52→  const { selectedFilePath, fileTreePinned, setFileTreePinned } = useWorkspaceLayout(workspace.id);
 53→  const diffViewerRef = useRef<ChangesDiffViewerRef>(null);
 54→  const [changesFilter, setChangesFilter] = useState<ChangesFilter>("all-changes");
 55→
 56→  const isReady = workspace.state === "ready";
 57→
 58→  // Fetch file change data
 59→  const { data: fileChangesData } = useFileChanges(
 60→    isReady ? workspace.id : null,
 61→    workspace.session_status,
 62→    isWatched,
 63→    workspace.state
 64→  );
 65→  const fileChanges = useMemo(() => fileChangesData?.files ?? [], [fileChangesData]);
 66→
 67→  // TODO: Wire up uncommitted/last-turn filters when backend endpoints exist.
 68→  // For now, changesFilter is always "all-changes" (other options are commented out
 69→  // in CHANGES_FILTER_OPTIONS). When adding new filters, fetch the extra data here
 70→  // and use a match() to select the active list.
 71→  const filteredFileChanges = fileChanges;
 72→
 73→  // Scroll the diff viewer to the clicked file
 74→  const handleFileClick = useCallback((path: string) => {
 75→    diffViewerRef.current?.scrollToFile(path);
 76→  }, []);
 77→
 78→  const handlePin = useCallback(() => setFileTreePinned(true), [setFileTreePinned]);
 79→  const handleUnpin = useCallback(() => setFileTreePinned(false), [setFileTreePinned]);
 80→
 81→  const activeFilterLabel = changesFilterLabel(changesFilter);
 82→
 83→  return (
 84→    <div className="flex h-full flex-col overflow-hidden">
 85→      {/* Header — filter dropdown (left) + review button (right) */}
 86→      <div className="border-border-subtle flex h-10 flex-shrink-0 items-center justify-between border-b px-4">
 87→        <DropdownMenu>
 88→          <DropdownMenuTrigger asChild>
 89→            <button
 90→              type="button"
 91→              className="text-text-muted hover:text-text-secondary ease flex items-center gap-1 rounded-lg px-1.5 py-1 text-sm transition-colors duration-200"
 92→            >
 93→              <SlidersHorizontal className="h-[11px] w-[11px]" />
 94→              <span>{activeFilterLabel}</span>
 95→              <ChevronDown className="h-[10px] w-[10px]" />
 96→            </button>
 97→          </DropdownMenuTrigger>
 98→          <DropdownMenuContent align="start" className="min-w-[140px]">
 99→            {CHANGES_FILTER_OPTIONS.map(([value, label]) => (
100→              <DropdownMenuItem
101→                key={value}
102→                onClick={() => setChangesFilter(value)}
103→                className="gap-2 text-xs"
104→              >
105→                <Check
106→                  className={cn("h-3 w-3", changesFilter === value ? "opacity-100" : "opacity-0")}
107→                />
108→                {label}
109→              </DropdownMenuItem>
110→            ))}
111→          </DropdownMenuContent>
112→        </DropdownMenu>
113→
114→        {onReview && filteredFileChanges.length > 0 && (
115→          <button
116→            type="button"
