  1→/**
  2→ * Workspace Layout Hook
  3→ * Provides workspace-specific layout state with proper store synchronization.
  4→ *
  5→ * Reads directly from the store and provides stable callbacks that update it.
  6→ *
  7→ * Usage:
  8→ * ```typescript
  9→ * const {
 10→ *   contentTab,
 11→ *   selectedFilePath,
 12→ *   setContentTab,
 13→ *   setSelectedFilePath,
 14→ * } = useWorkspaceLayout(workspaceId);
 15→ * ```
 16→ */
 17→
 18→import { useCallback } from "react";
 19→import { useShallow } from "zustand/react/shallow";
 20→import {
 21→  useWorkspaceLayoutStore,
 22→  workspaceLayoutActions,
 23→  defaultLayout,
 24→} from "../store/workspaceLayoutStore";
 25→import type { ContentTab } from "../store/workspaceLayoutStore";
 26→
 27→interface UseWorkspaceLayoutResult {
 28→  /** Current content panel tab (changes, files, terminal, browser, config, etc.) */
 29→  contentTab: ContentTab;
 30→  /** Currently selected file path (for highlighting in tree) */
 31→  selectedFilePath: string | null;
 32→  /** Whether sidebar is collapsed */
 33→  sidebarCollapsed: boolean;
 34→  /** Whether chat panel is collapsed */
 35→  chatPanelCollapsed: boolean;
 36→  /** Whether content panel is collapsed */
 37→  contentPanelCollapsed: boolean;
 38→  /** Whether file tree is pinned open (vs minimap mode) */
 39→  fileTreePinned: boolean;
 40→
 41→  /** Set the active content tab */
 42→  setContentTab: (tab: ContentTab) => void;
 43→  /** Set selected file path */
 44→  setSelectedFilePath: (path: string | null) => void;
 45→  /** Set sidebar collapsed state */
 46→  setSidebarCollapsed: (collapsed: boolean) => void;
 47→  /** Set chat panel collapsed state */
 48→  setChatPanelCollapsed: (collapsed: boolean) => void;
 49→  /** Set content panel collapsed state */
 50→  setContentPanelCollapsed: (collapsed: boolean) => void;
 51→  /** Set file tree pinned state */
 52→  setFileTreePinned: (pinned: boolean) => void;
 53→  /** Update multiple layout properties at once */
 54→  updateLayout: (updates: {
 55→    contentTab?: ContentTab;
 56→    selectedFilePath?: string | null;
 57→    sidebarCollapsed?: boolean;
 58→  }) => void;
 59→}
 60→
 61→export function useWorkspaceLayout(workspaceId: string | null): UseWorkspaceLayoutResult {
 62→  const layout = useWorkspaceLayoutStore(
 63→    useShallow((state) =>
 64→      workspaceId ? (state.layouts[workspaceId] ?? defaultLayout) : defaultLayout
 65→    )
 66→  );
 67→  const { setLayout } = workspaceLayoutActions;
 68→
 69→  const setContentTab = useCallback(
 70→    (tab: ContentTab) => {
 71→      if (workspaceId) {
 72→        setLayout(workspaceId, { activeContentTab: tab });
 73→      }
 74→    },
 75→    [workspaceId, setLayout]
 76→  );
 77→
 78→  const setSelectedFilePath = useCallback(
 79→    (path: string | null) => {
 80→      if (workspaceId) {
 81→        setLayout(workspaceId, { selectedFilePath: path });
 82→      }
 83→    },
 84→    [workspaceId, setLayout]
 85→  );
 86→
 87→  const setSidebarCollapsed = useCallback(
 88→    (collapsed: boolean) => {
 89→      if (workspaceId) {
 90→        setLayout(workspaceId, { sidebarCollapsed: collapsed });
 91→      }
 92→    },
 93→    [workspaceId, setLayout]
 94→  );
 95→
 96→  const setChatPanelCollapsed = useCallback(
 97→    (collapsed: boolean) => {
 98→      if (workspaceId) {
 99→        setLayout(workspaceId, { chatPanelCollapsed: collapsed });
100→      }
101→    },
102→    [workspaceId, setLayout]
103→  );
104→
105→  const setContentPanelCollapsed = useCallback(
106→    (collapsed: boolean) => {
107→      if (workspaceId) {
108→        setLayout(workspaceId, { contentPanelCollapsed: collapsed });
109→      }
110→    },
111→    [workspaceId, setLayout]
112→  );
113→
114→  const setFileTreePinned = useCallback(
115→    (pinned: boolean) => {
116→      if (workspaceId) {
117→        setLayout(workspaceId, { fileTreePinned: pinned });
118→      }
119→    },
120→    [workspaceId, setLayout]
121→  );
122→
123→  const updateLayout = useCallback(
124→    (updates: {
125→      contentTab?: ContentTab;
126→      selectedFilePath?: string | null;
127→      sidebarCollapsed?: boolean;
128→    }) => {
129→      if (!workspaceId) return;
130→
131→      const layoutUpdates: Parameters<typeof setLayout>[1] = {};
132→
133→      if (updates.contentTab !== undefined) {
134→        layoutUpdates.activeContentTab = updates.contentTab;
135→      }
136→      if (updates.selectedFilePath !== undefined) {
137→        layoutUpdates.selectedFilePath = updates.selectedFilePath;
138→      }
139→      if (updates.sidebarCollapsed !== undefined) {
140→        layoutUpdates.sidebarCollapsed = updates.sidebarCollapsed;
141→      }
142→
143→      setLayout(workspaceId, layoutUpdates);
144→    },
145→    [workspaceId, setLayout]
146→  );
147→
148→  return {
149→    contentTab: layout.activeContentTab ?? defaultLayout.activeContentTab,
150→    selectedFilePath: layout.selectedFilePath ?? null,
151→    sidebarCollapsed: layout.sidebarCollapsed,
152→    chatPanelCollapsed: layout.chatPanelCollapsed ?? false,
153→    contentPanelCollapsed: layout.contentPanelCollapsed ?? false,
154→    fileTreePinned: layout.fileTreePinned ?? defaultLayout.fileTreePinned,
155→
156→    setContentTab,
157→    setSelectedFilePath,
158→    setSidebarCollapsed,
159→    setChatPanelCollapsed,
160→    setContentPanelCollapsed,
161→    setFileTreePinned,
162→    updateLayout,
163→  };
164→}
