  7→/** Derive change status from line additions/deletions */
  8→export function getChangeStatus(change: FileChange): ChangeStatus {
  9→  if (change.additions > 0 && change.deletions === 0) return "added";
 10→  if (change.deletions > 0 && change.additions === 0) return "deleted";
 11→  return "modified";
