 50→    model: null,
 51→    session_error_category: null,
 52→    session_error_message: null,
 53→    latest_message_sent_at: null,
 54→    init_stage: null,
 55→    setup_status: "none",
 56→    error_message: null,
 57→    updated_at: new Date().toISOString(),
 58→    repo_name: repoName,
 59→    root_path: "",
 60→    workspace_path: "",
 61→  };
 62→}
